import React, { useEffect, useRef, useState } from 'react';
import { 
  CANVAS_WIDTH, CANVAS_HEIGHT, GRAVITY, TILE_SIZE, COLORS, PLAYER_WIDTH, PLAYER_HEIGHT, 
  MOVE_SPEED, JUMP_FORCE, TERMINAL_VELOCITY, PROJECTILE_SPEED, PROJECTILE_SIZE, SHOOT_COOLDOWN, 
  WINE_DURATION, WINE_SPEED_MULTIPLIER, WINE_JUMP_MULTIPLIER,
  ACCELERATION, FRICTION, AIR_FRICTION, COYOTE_TIME, JUMP_BUFFER,
  SWIM_SPEED, WATER_FRICTION, MELEE_RANGE, MELEE_DURATION, MELEE_COOLDOWN
} from '../constants';
import { Entity, Player, EntityType, GameStatus, GameState, EnemyVariant } from '../types';
import { levels } from '../levels';
import { audio } from '../audio';
import { ArrowLeft, ArrowRight, ArrowUp, Crosshair } from 'lucide-react';

interface GameCanvasProps {
  levelId: number;
  gameState: GameState;
  setGameState: React.Dispatch<React.SetStateAction<GameState>>;
  onLevelComplete: () => void;
  onPlayerHit: () => void;
  onGameOver: () => void;
}

interface Cloud {
  x: number;
  y: number;
  speed: number;
  size: number;
}

interface Tree {
  x: number;
  y: number;
  width: number;
  height: number;
  color: string;
}

interface Planet {
  x: number;
  y: number;
  size: number;
  color: string;
  hasRing: boolean;
  speed: number;
}

interface Particle {
  x: number;
  y: number;
  speedX: number;
  speedY: number;
  size: number;
  life: number;
  color?: string; 
}

export const GameCanvas: React.FC<GameCanvasProps> = ({ levelId, gameState, setGameState, onLevelComplete, onPlayerHit, onGameOver }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>(0);

  // Game State Refs
  const levelRef = useRef(levels.find(l => l.id === levelId) || levels[0]);

  const playerRef = useRef<Player>({
    id: 'hero',
    type: EntityType.PLAYER,
    pos: { ...levelRef.current.spawnPoint },
    size: { x: PLAYER_WIDTH, y: PLAYER_HEIGHT },
    vel: { x: 0, y: 0 },
    isGrounded: false,
    facingRight: true,
    isInvulnerable: false,
    invulnerableTimer: 0,
    shootCooldown: 0,
    drunkTimer: 0,
    coyoteTimer: 0,
    jumpBufferTimer: 0,
    isAttacking: false,
    attackTimer: 0
  });

  const entitiesRef = useRef<Entity[]>(JSON.parse(JSON.stringify(levelRef.current.entities)));
  const bulletsRef = useRef<Entity[]>([]); // Track active bullets
  const cameraRef = useRef({ x: 0, y: 0, shake: 0 }); // Added shake
  const keysRef = useRef<{ [key: string]: boolean }>({});

  // Environment Refs
  const cloudsRef = useRef<Cloud[]>([]);
  const treesRef = useRef<Tree[]>([]);
  const planetsRef = useRef<Planet[]>([]);
  const particlesRef = useRef<Particle[]>([]);

  // Init Environment
  useEffect(() => {
    // Clouds for normal levels
    cloudsRef.current = Array.from({ length: 8 }).map(() => ({
      x: Math.random() * CANVAS_WIDTH * 2,
      y: Math.random() * (CANVAS_HEIGHT / 2),
      speed: 0.2 + Math.random() * 0.5,
      size: 30 + Math.random() * 40
    }));

    // Trees for Train level
    treesRef.current = Array.from({ length: 15 }).map((_, i) => ({
       x: i * (CANVAS_WIDTH / 3) + Math.random() * 100,
       y: CANVAS_HEIGHT - 50, // Approx ground level for background
       width: 40 + Math.random() * 40,
       height: 100 + Math.random() * 150,
       color: Math.random() > 0.5 ? '#166534' : '#14532D'
    }));

    // Planets for Space level
    const planetColors = [COLORS.planetRed, COLORS.planetBlue, '#D1D5DB', '#FCD34D'];
    planetsRef.current = Array.from({ length: 6 }).map((_, i) => ({
       x: Math.random() * CANVAS_WIDTH * 2,
       y: Math.random() * (CANVAS_HEIGHT * 0.8),
       size: 20 + Math.random() * 60,
       color: planetColors[Math.floor(Math.random() * planetColors.length)],
       hasRing: Math.random() > 0.5,
       speed: 0.05 + Math.random() * 0.2
    }));

  }, []);

  // Reset level when ID changes
  useEffect(() => {
    const newLevel = levels.find(l => l.id === levelId) || levels[0];
    levelRef.current = newLevel;
    entitiesRef.current = JSON.parse(JSON.stringify(newLevel.entities));
    bulletsRef.current = [];
    playerRef.current = {
      id: 'hero',
      type: EntityType.PLAYER,
      pos: { ...newLevel.spawnPoint },
      size: { x: PLAYER_WIDTH, y: PLAYER_HEIGHT },
      vel: { x: 0, y: 0 },
      isGrounded: false,
      facingRight: true,
      isInvulnerable: true, // Grace period on spawn
      invulnerableTimer: 60,
      shootCooldown: 0,
      drunkTimer: 0,
      coyoteTimer: 0,
      jumpBufferTimer: 0,
      isAttacking: false,
      attackTimer: 0
    };
    cameraRef.current.x = 0;
    cameraRef.current.shake = 0;
    particlesRef.current = []; 

    // Start BGM based on level weather/type
    let bgmType: 'NORMAL' | 'CAVE' | 'TOMB' | 'SPACE' | 'CREDITS' = 'NORMAL';
    if (newLevel.weather === 'CAVE') bgmType = 'CAVE';
    if (newLevel.weather === 'TOMB') bgmType = 'TOMB';
    if (newLevel.weather === 'SPACE') bgmType = 'SPACE';
    if (newLevel.weather === 'ARCTIC') bgmType = 'CREDITS'; // Use happy music for family level
    audio.startBGM(bgmType);

    return () => {
      audio.stopBGM();
    }
  }, [levelId]);

  // Handle "Rescue" or "Revive" synchronization
  useEffect(() => {
    if (gameState.status === GameStatus.PLAYING) {
        // If coming from revive, give invulnerability
        if (playerRef.current.invulnerableTimer === 0) {
             playerRef.current.isInvulnerable = true;
             playerRef.current.invulnerableTimer = 120;
        }

       // In SEA/SPACE levels, allow going deeper, but clamp at extreme depth or create walls
       const isFreeFly = levelRef.current.weather === 'SEA' || levelRef.current.weather === 'SPACE';
       const limit = isFreeFly ? levelRef.current.height + 200 : levelRef.current.height + 50;

       if (playerRef.current.pos.y > limit) {
           if (isFreeFly) {
               // Wall bounce
               playerRef.current.pos.y = limit - 10;
               playerRef.current.vel.y = -1;
           } else {
               // Fall death in other levels
               playerRef.current.pos = { ...levelRef.current.spawnPoint };
               playerRef.current.vel = { x: 0, y: 0 };
               cameraRef.current.x = Math.max(0, playerRef.current.pos.x - CANVAS_WIDTH / 3);
               handleDamage(playerRef.current); // Deduct life on fall
           }
       }
       keysRef.current = {}; 

        let bgmType: 'NORMAL' | 'CAVE' | 'TOMB' | 'SPACE' | 'CREDITS' = 'NORMAL';
        if (levelRef.current.weather === 'CAVE') bgmType = 'CAVE';
        if (levelRef.current.weather === 'TOMB') bgmType = 'TOMB';
        if (levelRef.current.weather === 'SPACE') bgmType = 'SPACE';
        if (levelRef.current.weather === 'ARCTIC') bgmType = 'CREDITS';
        audio.startBGM(bgmType);
    } else {
       audio.stopBGM();
    }
  }, [gameState.status]);

  // Input Handling
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => { 
        keysRef.current[e.code] = true;
        // Jump Buffer: Record press even if in air
        if (e.code === 'Space' || e.code === 'ArrowUp') {
            playerRef.current.jumpBufferTimer = JUMP_BUFFER;
        }
    };
    const handleKeyUp = (e: KeyboardEvent) => { keysRef.current[e.code] = false; };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  const checkCollision = (rect1: Entity, rect2: Entity) => {
    return (
      rect1.pos.x < rect2.pos.x + rect2.size.x &&
      rect1.pos.x + rect1.size.x > rect2.pos.x &&
      rect1.pos.y < rect2.pos.y + rect2.size.y &&
      rect1.pos.y + rect1.size.y > rect2.pos.y
    );
  };

  const addShake = (amount: number) => {
      cameraRef.current.shake = amount;
  };

  const spawnEnemy = (spawner: Entity) => {
      const variant = spawner.spawnVariant || 'NORMAL';
      let width = 30;
      let height = 30;
      let speed = 2;
      let health = 1;
      let color = COLORS.enemy;

      if (variant === 'TANK') {
        width = 50;
        height = 50;
        speed = 1;
        health = 3;
        color = COLORS.enemyTank;
      } else if (variant === 'FAST') {
        width = 25;
        height = 25;
        speed = 4;
        health = 1;
        color = COLORS.enemyFast;
      } else if (variant === 'BAT' || variant === 'BIRD') {
        width = 30;
        height = 20;
        speed = 3;
        health = 1;
        color = variant === 'BIRD' ? COLORS.enemyBird : COLORS.enemyBat;
      } else if (variant === 'SLIME') {
        width = 30;
        height = 20;
        speed = 1;
        health = 2;
        color = COLORS.enemySlime;
      } else if (variant === 'FISH') {
        width = 35;
        height = 25;
        speed = 2.5;
        health = 1;
        color = COLORS.enemyFish;
      } else if (variant === 'SKELETON') {
        width = 25;
        height = 45;
        speed = 2;
        health = 2;
        color = COLORS.enemySkeleton;
      } else if (variant === 'MUMMY') {
        width = 30;
        height = 45;
        speed = 1;
        health = 4;
        color = COLORS.enemyMummy;
      } else if (variant === 'ZOMBIE') {
        width = 30;
        height = 45;
        speed = 1.5;
        health = 3;
        color = COLORS.enemyZombie;
      } else if (variant === 'SPIDER') {
        width = 30;
        height = 25;
        speed = 2;
        health = 1;
        color = COLORS.enemySpider;
      } else if (variant === 'ALIEN') {
        width = 25;
        height = 35;
        speed = 2;
        health = 2;
        color = COLORS.enemyAlien;
      } else if (variant === 'UFO') {
        width = 40;
        height = 25;
        speed = 4;
        health = 2;
        color = COLORS.enemyUfo;
      } else if (variant === 'METEOR') {
        width = 35;
        height = 35;
        speed = 4;
        health = 1;
        color = COLORS.meteor;
      }

      const dir = Math.random() > 0.5 ? 1 : -1;

      let spawnY = spawner.pos.y - height + spawner.size.y; 
      // Bats/Birds/UFOs/Meteors spawn with offsets
      if (variant === 'BAT' || variant === 'BIRD' || variant === 'UFO') {
          spawnY -= (variant === 'UFO' ? 100 + Math.random() * 50 : 100); 
      }
      if (variant === 'METEOR') {
          // Meteors spawn anywhere vertically around the spawner to simulate a field
          spawnY = spawner.pos.y - 300 + Math.random() * 400;
      }

      const enemy: Entity = {
        id: `spawned_${Date.now()}_${Math.random()}`,
        type: EntityType.ENEMY,
        pos: { x: spawner.pos.x, y: spawnY }, 
        size: { x: width, y: height },
        vel: { x: speed * dir, y: 0 },
        patrolStart: spawner.pos.x - 400,
        patrolEnd: spawner.pos.x + 400,
        enemyVariant: variant,
        health,
        maxHealth: health,
        color
      };

      if (variant === 'SPIDER') {
        enemy.vel.x = 0;
        enemy.vel.y = speed;
        enemy.initialY = spawnY;
      }

      if (variant === 'METEOR') {
          enemy.vel.x = -speed - Math.random() * 2; 
          enemy.vel.y = (Math.random() - 0.5) * 1; 
          enemy.patrolStart = -99999;
          enemy.patrolEnd = 99999;
      }

      entitiesRef.current.push(enemy);

      const dist = Math.abs(spawner.pos.x - playerRef.current.pos.x);
      if (dist < 800 && variant !== 'METEOR') { 
          audio.playRoar();
      }
  };

  const updateEnvironment = () => {
    const player = playerRef.current;
    const weather = levelRef.current.weather;

    // 1. Moving Background Elements
    if (weather === 'TRAIN') {
        cloudsRef.current.forEach(cloud => {
            cloud.x -= cloud.speed * 3;
            if (cloud.x + cloud.size * 2 < 0) {
                cloud.x = CANVAS_WIDTH * 2 + Math.random() * 200;
                cloud.y = Math.random() * (CANVAS_HEIGHT / 2);
            }
        });
        treesRef.current.forEach(tree => {
             tree.x -= 5;
             if (tree.x + tree.width < -100) {
                 tree.x = CANVAS_WIDTH + 100 + Math.random() * 300;
                 tree.height = 100 + Math.random() * 150;
                 tree.y = CANVAS_HEIGHT - 30; 
             }
        });
        if (particlesRef.current.length < 50) {
            const spawnX = cameraRef.current.x + CANVAS_WIDTH + Math.random() * 100;
            particlesRef.current.push({
                x: spawnX,
                y: Math.random() * CANVAS_HEIGHT,
                speedX: -10 - Math.random() * 5,
                speedY: 0,
                size: 1 + Math.random() * 2,
                life: 0.5,
                color: 'rgba(255, 255, 255, 0.2)'
            });
        }
    }
    else if (weather === 'SPACE') {
        // Move Planets slowly
        planetsRef.current.forEach(p => {
             p.x -= p.speed;
             if (p.x + p.size < 0) {
                 p.x = CANVAS_WIDTH * 1.5 + Math.random() * 500;
                 p.y = Math.random() * (CANVAS_HEIGHT * 0.8);
             }
        });
    }
    else if (weather !== 'CAVE' && weather !== 'SEA' && weather !== 'TOMB') {
        cloudsRef.current.forEach(cloud => {
        cloud.x -= cloud.speed;
        if (cloud.x + cloud.size * 2 < 0) {
            cloud.x = CANVAS_WIDTH * 2 + Math.random() * 200;
            cloud.y = Math.random() * (CANVAS_HEIGHT / 2);
        }
        });
    }

    // 2. Weather Particles
    if (weather === 'SEA') {
         if (particlesRef.current.length < 50) {
            const spawnX = cameraRef.current.x + Math.random() * CANVAS_WIDTH;
            particlesRef.current.push({
                x: spawnX,
                y: CANVAS_HEIGHT + 10,
                speedX: (Math.random() - 0.5) * 0.5,
                speedY: -1 - Math.random(),
                size: 2 + Math.random() * 4,
                life: 1,
                color: 'rgba(255, 255, 255, 0.4)'
            });
        }
    } 
    else if (weather === 'TOMB') {
        if (particlesRef.current.length < 30) {
            const spawnX = cameraRef.current.x + Math.random() * CANVAS_WIDTH;
            particlesRef.current.push({
                x: spawnX,
                y: Math.random() * CANVAS_HEIGHT,
                speedX: -2 - Math.random(),
                speedY: (Math.random() - 0.5) * 0.5,
                size: 1 + Math.random() * 2,
                life: 1,
                color: '#D97706'
            });
        }
    }
    else if (weather === 'CAVE') {
        if (particlesRef.current.length < 50) {
            const spawnX = Math.random() * CANVAS_WIDTH;
            particlesRef.current.push({
                x: spawnX,
                y: -10,
                speedX: 0,
                speedY: 4 + Math.random() * 2,
                size: 2,
                life: 1,
                color: '#525252'
            });
        }
    } 
    else if (weather === 'ARCTIC' || weather === 'SNOW') {
        // Snowing
        if (particlesRef.current.length < 200) {
            const spawnX = Math.random() * CANVAS_WIDTH + cameraRef.current.x - 100;
            particlesRef.current.push({
                x: spawnX,
                y: -10,
                speedX: (Math.random() - 0.5) * 1, // Gentle drift
                speedY: 1 + Math.random() * 2, // Slow fall
                size: 2 + Math.random() * 3,
                life: 1,
                color: '#FFFFFF'
            });
        }
    }
    else if (weather !== 'SUNNY' && weather !== 'TRAIN' && weather !== 'SPACE') { // Standard Rain
       if (particlesRef.current.length < 150) {
          const spawnX = Math.random() * CANVAS_WIDTH;
          particlesRef.current.push({
             x: spawnX,
             y: -10,
             speedX: weather === 'RAIN' ? -1 : Math.sin(Date.now() / 1000), 
             speedY: weather === 'RAIN' ? 8 + Math.random() * 4 : 1 + Math.random(), 
             size: weather === 'RAIN' ? 2 : 3 + Math.random() * 2,
             life: 1
          });
       }
    }

    // 3. Drunk Particles
    if (player.drunkTimer > 0) {
       for (let k = 0; k < 2; k++) {
           particlesRef.current.push({
               x: player.pos.x + Math.random() * player.size.x,
               y: player.pos.y + player.size.y,
               speedX: (Math.random() - 0.5) * 2,
               speedY: -1 - Math.random() * 3, 
               size: Math.random() * 6 + 2,
               life: 0.8,
               color: Math.random() > 0.5 ? '#EF4444' : '#F59E0B'
           });
       }
    }

    // Update Particles
    for (let i = particlesRef.current.length - 1; i >= 0; i--) {
      const p = particlesRef.current[i];
      p.x += p.speedX;
      p.y += p.speedY;

      if (p.color && p.color !== '#525252' && !p.color.startsWith('rgba') && p.color !== '#D97706' && p.color !== '#FFFFFF') { 
          p.life -= 0.05;
          p.size *= 0.95; 
      }
      // Bubbles check
      else if (weather === 'SEA' && p.y < 0) {
           particlesRef.current.splice(i, 1);
           continue;
      }

      if (p.y > CANVAS_HEIGHT && weather !== 'SEA') {
         // Snow wrapping for Arctic
         if (weather === 'ARCTIC' || weather === 'SNOW') {
             p.y = -10;
             p.x = Math.random() * CANVAS_WIDTH + cameraRef.current.x - 100;
         } else {
             particlesRef.current.splice(i, 1);
         }
      } else if (p.color && !p.color.startsWith('rgba') && p.color !== '#D97706' && p.color !== '#FFFFFF' && p.life <= 0) {
         particlesRef.current.splice(i, 1);
      } else if (weather === 'TOMB' && p.x < cameraRef.current.x - 50) {
         particlesRef.current.splice(i, 1);
      } else if (weather === 'TRAIN' && p.x < cameraRef.current.x - 100) {
         particlesRef.current.splice(i, 1);
      }
    }
  };

  const update = () => {
    updateEnvironment();

    if (gameState.status !== GameStatus.PLAYING) return;

    const player = playerRef.current;
    const entities = entitiesRef.current;
    const bullets = bulletsRef.current;
    const weather = levelRef.current.weather;
    const isSeaLevel = weather === 'SEA';
    const isSpaceLevel = weather === 'SPACE'; 
    const isTombLevel = weather === 'TOMB';
    const isTrainLevel = weather === 'TRAIN';
    const isArcticLevel = weather === 'ARCTIC';

    // --- Player State ---
    if (player.drunkTimer > 0) {
        player.drunkTimer--;
    }
    if (player.jumpBufferTimer > 0) {
        player.jumpBufferTimer--;
    }
    if (player.attackTimer && player.attackTimer > 0) {
        player.attackTimer--;
        if (player.attackTimer <= 0) player.isAttacking = false;
    }

    // Decrease shake
    if (cameraRef.current.shake > 0) {
        cameraRef.current.shake *= 0.9;
        if (cameraRef.current.shake < 0.5) cameraRef.current.shake = 0;
    }

    // --- Player Action: Shooting / Throwing ---
    if (player.shootCooldown > 0) player.shootCooldown--;

    // Disable shooting in Family Level (Arctic)
    if (!isArcticLevel && (keysRef.current['KeyF'] || keysRef.current['KeyJ']) && player.shootCooldown <= 0) {
        player.shootCooldown = SHOOT_COOLDOWN;
        if (player.drunkTimer > 0) player.shootCooldown = SHOOT_COOLDOWN / 2;

        const isBow = levelId === 3 || levelId === 4; 

        const bVelX = player.facingRight ? PROJECTILE_SPEED : -PROJECTILE_SPEED;

        let spawnY = player.pos.y + player.size.y / 2 - 4;

        const bPosX = player.facingRight 
            ? player.pos.x + player.size.x 
            : player.pos.x - PROJECTILE_SIZE;

        bullets.push({
            id: `b_${Date.now()}`,
            type: EntityType.PROJECTILE,
            pos: { x: bPosX, y: spawnY },
            size: { x: PROJECTILE_SIZE, y: PROJECTILE_SIZE }, 
            vel: { x: bVelX, y: 0 }
        });

        audio.playShoot();
        addShake(2); // Subtle recoil shake
    }

    // --- Update Bullets ---
    for (let i = bullets.length - 1; i >= 0; i--) {
        const b = bullets[i];
        b.pos.x += b.vel.x;

        const distFromCam = Math.abs(b.pos.x - cameraRef.current.x);
        if (distFromCam > CANVAS_WIDTH + 100) {
            bullets.splice(i, 1);
            continue;
        }

        let bulletHit = false;

        for (const ent of entities) {
            if (ent.isDead) continue; 

            if (ent.type === EntityType.ENEMY) {
                // Don't hurt family!
                if (ent.enemyVariant && ent.enemyVariant.startsWith('FAMILY')) continue;

                if (checkCollision(b, ent)) {
                    bulletHit = true;
                    ent.health = (ent.health || 1) - 1;
                    if (ent.health <= 0) {
                        ent.isDead = true;
                        setGameState(prev => ({ ...prev, score: prev.score + (ent.enemyVariant === 'TANK' || ent.enemyVariant === 'ZOMBIE' || ent.enemyVariant === 'UFO' ? 500 : 200) }));
                        audio.playKill();
                        addShake(10); // Big shake for kill
                    } else {
                        ent.pos.x += b.vel.x > 0 ? 5 : -5;
                        audio.playDamage();
                        addShake(2); // Hit shake
                    }
                    break;
                }
            } else if (ent.type === EntityType.PLATFORM) {
                if (checkCollision(b, ent)) {
                    bulletHit = true;
                    break;
                }
            } else if (ent.type === EntityType.BREAKABLE_WALL) {
                if (checkCollision(b, ent)) {
                    bulletHit = true;
                    if (isTombLevel) {
                         ent.isDead = true;
                         audio.playDig();
                         addShake(5);
                         for (let k = 0; k < 5; k++) {
                            particlesRef.current.push({
                                x: ent.pos.x + Math.random() * ent.size.x,
                                y: ent.pos.y + Math.random() * ent.size.y,
                                speedX: (Math.random() - 0.5) * 5,
                                speedY: (Math.random() - 0.5) * 5,
                                size: 3,
                                life: 1,
                                color: COLORS.sandWall
                            });
                         }
                    }
                    break;
                }
            }
        }

        if (bulletHit) {
            bullets.splice(i, 1);
        }
    }


    // --- Player Movement ---
    const maxSpeed = player.drunkTimer > 0 ? MOVE_SPEED * WINE_SPEED_MULTIPLIER : MOVE_SPEED;
    const jumpForce = player.drunkTimer > 0 ? JUMP_FORCE * WINE_JUMP_MULTIPLIER : JUMP_FORCE;

    const isFreeFly = isSeaLevel || isSpaceLevel;

    if (isFreeFly) {
        // --- SWIMMING / FLYING PHYSICS ---
        // X Movement
        if (keysRef.current['ArrowLeft']) {
            player.vel.x -= ACCELERATION;
            player.facingRight = false;
        } else if (keysRef.current['ArrowRight']) {
            player.vel.x += ACCELERATION;
            player.facingRight = true;
        }
        // Y Movement
        if (keysRef.current['ArrowUp']) {
            player.vel.y -= ACCELERATION;
        } else if (keysRef.current['ArrowDown']) {
            player.vel.y += ACCELERATION;
        }

        // Apply Drag
        player.vel.x *= WATER_FRICTION;
        player.vel.y *= WATER_FRICTION;

        // Cap Speeds
        if (player.vel.x > SWIM_SPEED) player.vel.x = SWIM_SPEED;
        if (player.vel.x < -SWIM_SPEED) player.vel.x = -SWIM_SPEED;
        if (player.vel.y > SWIM_SPEED) player.vel.y = SWIM_SPEED;
        if (player.vel.y < -SWIM_SPEED) player.vel.y = -SWIM_SPEED;

    } else {
        // --- LAND PHYSICS ---
        // Horizontal Movement with Acceleration
        if (keysRef.current['ArrowLeft']) {
            player.vel.x -= ACCELERATION;
            player.facingRight = false;
        } else if (keysRef.current['ArrowRight']) {
            player.vel.x += ACCELERATION;
            player.facingRight = true;
        } else {
            // Friction
            const friction = player.isGrounded ? FRICTION : AIR_FRICTION;
            player.vel.x *= friction;
            if (Math.abs(player.vel.x) < 0.1) player.vel.x = 0;
        }

        // Clamp speed
        if (player.vel.x > maxSpeed) player.vel.x = maxSpeed;
        if (player.vel.x < -maxSpeed) player.vel.x = -maxSpeed;

        // Coyote Time Logic
        if (player.isGrounded) {
            player.coyoteTimer = COYOTE_TIME;
        } else {
            if (player.coyoteTimer > 0) player.coyoteTimer--;
        }

        // Jump Logic (Buffer + Coyote)
        if (player.jumpBufferTimer > 0 && player.coyoteTimer > 0) {
            player.vel.y = jumpForce;
            player.isGrounded = false;
            player.coyoteTimer = 0; // Consume coyote time
            player.jumpBufferTimer = 0; // Consume buffer
            audio.playJump();
        }

        // Variable Jump Height (Release key to fall faster)
        if (player.vel.y < 0 && !keysRef.current['Space'] && !keysRef.current['ArrowUp']) {
            player.vel.y *= 0.5;
        }

        // --- Physics ---
        player.vel.y += GRAVITY;
        if (player.vel.y > TERMINAL_VELOCITY) player.vel.y = TERMINAL_VELOCITY;
    }

    // --- APPLY VELOCITY ---
    player.pos.x += player.vel.x;
    if (isFreeFly) player.isGrounded = false; // Always floating

    // Bounds Check X
    if (player.pos.x < 0) player.pos.x = 0;
    if (player.pos.x > levelRef.current.width - player.size.x) player.pos.x = levelRef.current.width - player.size.x;

    // X Collisions
    for (const ent of entities) {
      if (ent.isDead) continue; 

      if (ent.type === EntityType.PLATFORM || ent.type === EntityType.BREAKABLE_WALL) {
        if (checkCollision(player, ent)) {
          if (player.vel.x > 0) {
            player.pos.x = ent.pos.x - player.size.x;
            player.vel.x = 0; 
          } else if (player.vel.x < 0) {
            player.pos.x = ent.pos.x + ent.size.x;
            player.vel.x = 0;
          }
        }
      }
    }

    player.pos.y += player.vel.y;

    // Y Collisions
    let landed = false;
    for (const ent of entities) {
      if (ent.isDead) continue; 

      if (ent.type === EntityType.PLATFORM || ent.type === EntityType.BREAKABLE_WALL) {
        if (checkCollision(player, ent)) {
          if (player.vel.y > 0) {
            player.pos.y = ent.pos.y - player.size.y;
            player.vel.y = 0;
            landed = true;
          } else if (player.vel.y < 0) {
            player.pos.y = ent.pos.y + ent.size.y;
            player.vel.y = 0;
          }
        }
      }
    }
    player.isGrounded = landed;

    if (!isFreeFly && player.pos.y > levelRef.current.height + 100) {
      onGameOver();
      return;
    }

    // --- Interactables & Spawners ---
    if (player.isInvulnerable) {
      player.invulnerableTimer--;
      if (player.invulnerableTimer <= 0) player.isInvulnerable = false;
    }

    entities.forEach(ent => {
      if (ent.isDead) return;

      if (ent.type === EntityType.ENEMY) {
        // Special logic for Bats/Fish/Spiders/Birds/UFO/Family
        if (ent.enemyVariant && ent.enemyVariant.startsWith('FAMILY')) {
             // Family members walk right
             ent.pos.x += ent.vel.x;
             // Keep up with player if they fall behind too much? Nah, let them walk at their pace
             if (ent.pos.x > levelRef.current.width) ent.pos.x = 0; // Loop? No, level is finite.
        } else if (ent.enemyVariant === 'BAT' || ent.enemyVariant === 'BIRD') {
             ent.pos.y += Math.sin(Date.now() / 200) * 1;
             ent.pos.x += ent.vel.x;
        } else if (ent.enemyVariant === 'FISH') {
             ent.pos.x += ent.vel.x;
             ent.pos.y += Math.cos(Date.now() / 400) * 0.5;
        } else if (ent.enemyVariant === 'UFO') {
             ent.pos.x += ent.vel.x;
             ent.pos.y += Math.sin(Date.now() / 300) * 1.5; // UFO Hover
        } else if (ent.enemyVariant === 'SPIDER') {
             const yOffset = Math.sin(Date.now() / 500) * 80;
             ent.pos.y = (ent.initialY || ent.pos.y) + yOffset;
        } else if (ent.enemyVariant === 'SKELETON' || ent.enemyVariant === 'ZOMBIE') {
             ent.pos.x += ent.vel.x;
        } else if (ent.enemyVariant === 'MUMMY') {
             ent.pos.x += ent.vel.x * 0.5;
        } else if (ent.enemyVariant === 'METEOR') {
             ent.pos.x += ent.vel.x;
             ent.pos.y += ent.vel.y;
        } else {
             ent.pos.x += ent.vel.x;
        }

        if (ent.patrolEnd && ent.pos.x >= ent.patrolEnd) ent.vel.x = -Math.abs(ent.vel.x);
        if (ent.patrolStart && ent.pos.x <= ent.patrolStart) ent.vel.x = Math.abs(ent.vel.x);
      } 
      else if (ent.type === EntityType.SPAWNER) {
          if (ent.spawnCooldown) {
              ent.timeUntilSpawn = (ent.timeUntilSpawn || 0) + 1;
              if (ent.timeUntilSpawn >= ent.spawnCooldown) {
                  // Spawn logic check
                  const dist = Math.abs(ent.pos.x - player.pos.x);
                  let shouldSpawn = false;

                  if (ent.spawnVariant === 'METEOR') {
                      if (dist < 1000) shouldSpawn = true;
                  } else {
                      if (dist < 800 && dist > 100) shouldSpawn = true;
                  }

                  if (shouldSpawn) {
                      spawnEnemy(ent);
                      ent.timeUntilSpawn = 0;
                  }
              }
          }
      }

      // Collisions
      if (checkCollision(player, ent)) {
        if (ent.type === EntityType.COIN) {
          ent.isDead = true;
          setGameState(prev => ({ ...prev, score: prev.score + 100, coinsCollected: prev.coinsCollected + 1 }));
          audio.playCoin();
        } else if (ent.type === EntityType.WINE) {
          ent.isDead = true;
          player.drunkTimer = WINE_DURATION;
          audio.playPowerUp();
          setGameState(prev => ({ ...prev, score: prev.score + 500 }));

          for (let k = 0; k < 20; k++) {
             particlesRef.current.push({
                 x: player.pos.x + player.size.x / 2,
                 y: player.pos.y + player.size.y / 2,
                 speedX: (Math.random() - 0.5) * 15,
                 speedY: (Math.random() - 0.5) * 15,
                 size: Math.random() * 6 + 4,
                 life: 1.0,
                 color: Math.random() > 0.5 ? '#EF4444' : '#F59E0B'
             });
          }

        } else if (ent.type === EntityType.POTION) {
            ent.isDead = true;
            audio.playHeal();
            setGameState(prev => {
                let newLives = prev.lives;
                let newMaxLives = prev.maxLives;

                if (newLives < newMaxLives) {
                    newLives += 1;
                } else {
                    // Overheal: Increase max HP
                    newMaxLives += 1;
                    newLives = newMaxLives;
                }

                return { ...prev, lives: newLives, maxLives: newMaxLives };
            });

            // Healing Particles
            for (let k = 0; k < 15; k++) {
                particlesRef.current.push({
                    x: ent.pos.x + ent.size.x / 2,
                    y: ent.pos.y + ent.size.y / 2,
                    speedX: (Math.random() - 0.5) * 4,
                    speedY: -2 - Math.random() * 4,
                    size: Math.random() * 4 + 2,
                    life: 1.5,
                    color: '#F472B6' // Pink hearts/sparkles
                });
            }

        } else if (ent.type === EntityType.FLAG || ent.type === EntityType.TROPHY) {
          onLevelComplete();
          audio.playWin();
        } else if (ent.type === EntityType.SPIKE) {
           if (!player.isInvulnerable) handleDamage(player);
        } else if (ent.type === EntityType.ENEMY) {
          // If Family, just bounce lightly or ignore damage
          if (ent.enemyVariant && ent.enemyVariant.startsWith('FAMILY')) {
              // Friendly collision: maybe spawn a heart?
              if (Math.random() > 0.95) {
                   particlesRef.current.push({
                    x: ent.pos.x + ent.size.x / 2,
                    y: ent.pos.y,
                    speedX: 0,
                    speedY: -1,
                    size: 3,
                    life: 0.5,
                    color: '#F472B6' // Heart color
                });
              }
              return; 
          }

          const hitFromTop = !isFreeFly && player.vel.y > 0 && (player.pos.y + player.size.y) < (ent.pos.y + ent.size.y * 0.7);
          if (hitFromTop) {
            ent.isDead = true;
            player.vel.y = JUMP_FORCE / 2;
            setGameState(prev => ({ ...prev, score: prev.score + 200 }));
            audio.playKill();
            addShake(5);
          } else {
             if (!player.isInvulnerable) handleDamage(player);
          }
        }
      }
    });

    // --- Camera Follow with Lookahead ---
    const lookAhead = player.facingRight ? 100 : -50;
    const targetCamX = player.pos.x - CANVAS_WIDTH / 3 + lookAhead;
    cameraRef.current.x += (targetCamX - cameraRef.current.x) * 0.05; // Smoother lerp
    if (cameraRef.current.x < 0) cameraRef.current.x = 0;
    const maxCamX = levelRef.current.width - CANVAS_WIDTH;
    if (cameraRef.current.x > maxCamX) cameraRef.current.x = maxCamX;
  };

  const handleDamage = (player: Player) => {
    player.isInvulnerable = true;
    player.invulnerableTimer = 120;
    player.vel.y = -6;
    player.vel.x = player.facingRight ? -4 : 4;
    onPlayerHit();
    audio.playDamage();
    addShake(15); // Big shake on damage
  };

  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const cameraX = Math.floor(cameraRef.current.x);
    const player = playerRef.current;
    const weather = levelRef.current.weather;
    const bullets = bulletsRef.current;
    const isSeaLevel = weather === 'SEA';
    const isSpaceLevel = weather === 'SPACE';
    const isTombLevel = weather === 'TOMB';
    const isTrainLevel = weather === 'TRAIN';
    const isArcticLevel = weather === 'ARCTIC';

    const isBowLevel = levelId === 3 || levelId === 4;
    const isShovelLevel = levelId === 5;
    const isShurikenLevel = levelId === 6;
    const isLaserLevel = isSpaceLevel; // Level 7

    // 1. Background
    ctx.fillStyle = levelRef.current.backgroundColor;
    ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

    // Apply Shake
    const shakeX = (Math.random() - 0.5) * cameraRef.current.shake;
    const shakeY = (Math.random() - 0.5) * cameraRef.current.shake;

    // 2. Stars for Space
    if (isSpaceLevel) {
        ctx.fillStyle = '#FFF';
        for (let i = 0; i < 100; i++) {
            const starX = (i * 123 + cameraX * 0.05) % CANVAS_WIDTH;
            const starY = (i * 87) % CANVAS_HEIGHT;
            ctx.globalAlpha = Math.random() * 0.5 + 0.3;
            ctx.fillRect(starX, starY, Math.random() > 0.9 ? 2 : 1, Math.random() > 0.9 ? 2 : 1);
        }
        ctx.globalAlpha = 1.0;

        // Draw Planets
        planetsRef.current.forEach(p => {
             const parallaxX = p.x - (cameraX * 0.1); 
             const renderX = ((parallaxX % (CANVAS_WIDTH * 2)) + (CANVAS_WIDTH * 2)) % (CANVAS_WIDTH * 2) - 100;

             ctx.fillStyle = p.color;
             ctx.beginPath();
             ctx.arc(renderX, p.y, p.size, 0, Math.PI * 2);
             ctx.fill();

             // Craters / Details
             ctx.fillStyle = 'rgba(0,0,0,0.1)';
             ctx.beginPath();
             ctx.arc(renderX - p.size*0.3, p.y - p.size*0.2, p.size*0.2, 0, Math.PI * 2);
             ctx.fill();

             if (p.hasRing) {
                 ctx.strokeStyle = COLORS.planetRing;
                 ctx.lineWidth = 4;
                 ctx.beginPath();
                 ctx.ellipse(renderX, p.y, p.size * 1.6, p.size * 0.4, 0.2, 0, Math.PI * 2);
                 ctx.stroke();
             }
        });
    }

    // Clouds & Background Elements (Standard)
    if (weather !== 'CAVE' && weather !== 'SEA' && weather !== 'TOMB' && weather !== 'SPACE') {
        if (isTrainLevel) {
            treesRef.current.forEach(tree => {
                ctx.fillStyle = tree.color;
                ctx.beginPath();
                ctx.moveTo(tree.x + tree.width/2, tree.y - tree.height);
                ctx.lineTo(tree.x + tree.width, tree.y);
                ctx.lineTo(tree.x, tree.y);
                ctx.fill();
            });
        }

        ctx.fillStyle = 'rgba(255, 255, 255, 0.6)';
        cloudsRef.current.forEach(cloud => {
            const parallaxX = cloud.x - (cameraX * 0.2); 
            const renderX = ((parallaxX % (CANVAS_WIDTH * 2)) + (CANVAS_WIDTH * 2)) % (CANVAS_WIDTH * 2) - 200;
            ctx.beginPath();
            ctx.arc(renderX, cloud.y, cloud.size, 0, Math.PI * 2);
            ctx.arc(renderX + cloud.size * 0.8, cloud.y + cloud.size * 0.2, cloud.size * 0.9, 0, Math.PI * 2);
            ctx.arc(renderX - cloud.size * 0.8, cloud.y + cloud.size * 0.1, cloud.size * 0.7, 0, Math.PI * 2);
            ctx.fill();
        });
    }

    ctx.save();
    ctx.translate(-cameraX + shakeX, shakeY);

    // 3. Draw Level Entities
    entitiesRef.current.forEach(ent => {
      if (ent.isDead) return;
      if (ent.type === EntityType.SPAWNER) return;

      if (ent.type === EntityType.PLATFORM) {
        if (isSeaLevel) {
            ctx.fillStyle = COLORS.rock;
            ctx.fillRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);
        } else if (isSpaceLevel) {
             // Space Debris / Metal Platforms
             ctx.fillStyle = COLORS.asteroid;
             ctx.fillRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);
             // Tech lines
             ctx.strokeStyle = '#64748B';
             ctx.lineWidth = 2;
             ctx.strokeRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);
             ctx.beginPath();
             ctx.moveTo(ent.pos.x, ent.pos.y);
             ctx.lineTo(ent.pos.x + ent.size.x, ent.pos.y + ent.size.y);
             ctx.stroke();

        } else if (isTrainLevel && ent.id.includes('train_car')) {
            // Draw Train Roof
            ctx.fillStyle = COLORS.trainCar;
            ctx.fillRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);

            // Draw Rivets
            ctx.fillStyle = '#334155';
            for (let i = 0; i < ent.size.x; i += 20) {
                ctx.beginPath();
                ctx.arc(ent.pos.x + i + 10, ent.pos.y + 5, 2, 0, Math.PI*2);
                ctx.fill();
            }

            // Wheels
            const wheelY = ent.pos.y + ent.size.y;
            ctx.fillStyle = COLORS.trainWheel;
            const wheelRadius = 15;
            for (let i = 20; i < ent.size.x; i += 60) {
                 ctx.beginPath();
                 ctx.arc(ent.pos.x + i, wheelY + 5, wheelRadius, 0, Math.PI*2);
                 ctx.fill();
                 ctx.fillStyle = '#475569'; 
                 ctx.beginPath();
                 ctx.arc(ent.pos.x + i, wheelY + 5, 5, 0, Math.PI*2);
                 ctx.fill();

                 // Connecting rod
                 if (i + 60 < ent.size.x) {
                     ctx.fillStyle = '#94A3B8';
                     ctx.fillRect(ent.pos.x + i, wheelY + 5, 60, 4);
                 }
            }

            // Windows
            if (ent.size.y > 30) {
                ctx.fillStyle = COLORS.trainWindow;
                ctx.fillRect(ent.pos.x + 10, ent.pos.y + 10, 40, 20);
                ctx.fillStyle = '#000'; // Frame
                ctx.strokeRect(ent.pos.x + 10, ent.pos.y + 10, 40, 20);
            }

        } else {
            ctx.fillStyle = levelRef.current.groundColor || COLORS.ground;
            ctx.fillRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);

            if (ent.size.y > 10) {
               ctx.fillStyle = levelRef.current.groundColor ? (levelRef.current.groundColor === COLORS.ice ? '#D6F2FE' : '#171717') : COLORS.dirt;
               ctx.globalAlpha = 0.3;
               ctx.fillRect(ent.pos.x, ent.pos.y + 10, ent.size.x, ent.size.y - 10);
               ctx.globalAlpha = 1.0;
            }
            ctx.strokeStyle = levelRef.current.groundColor === COLORS.ice ? '#7DD3FC' : '#000';
            ctx.lineWidth = 2;
            ctx.strokeRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);
        }
      } 
      else if (ent.type === EntityType.BREAKABLE_WALL) {
          ctx.fillStyle = COLORS.sandWall;
          ctx.fillRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);
          ctx.strokeStyle = '#B45309';
          ctx.lineWidth = 2;
          ctx.beginPath();
          ctx.moveTo(ent.pos.x, ent.pos.y);
          ctx.lineTo(ent.pos.x + ent.size.x, ent.pos.y + ent.size.y);
          ctx.moveTo(ent.pos.x + ent.size.x, ent.pos.y);
          ctx.lineTo(ent.pos.x, ent.pos.y + ent.size.y);
          ctx.stroke();
          ctx.strokeRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);
      }
      else if (ent.type === EntityType.COIN) {
        ctx.fillStyle = COLORS.coin;
        ctx.beginPath();
        ctx.arc(ent.pos.x + ent.size.x/2, ent.pos.y + ent.size.y/2, ent.size.x/2, 0, Math.PI * 2);
        ctx.fill();
        ctx.fillStyle = COLORS.coinShine;
        ctx.beginPath();
        ctx.arc(ent.pos.x + ent.size.x/2 - 3, ent.pos.y + ent.size.y/2 - 3, 3, 0, Math.PI * 2);
        ctx.fill();
      }
      else if (ent.type === EntityType.WINE) {
        ctx.fillStyle = COLORS.wine;
        ctx.fillRect(ent.pos.x + 4, ent.pos.y + 10, 12, 20);
        ctx.fillRect(ent.pos.x + 7, ent.pos.y, 6, 10);
        ctx.fillStyle = COLORS.wineLabel;
        ctx.fillRect(ent.pos.x + 5, ent.pos.y + 15, 10, 8);
        ctx.strokeStyle = COLORS.wineLabel;
        ctx.strokeRect(ent.pos.x + 4, ent.pos.y + 10, 12, 20);
        ent.pos.y += Math.sin(Date.now() / 150) * 0.3;
      }
      else if (ent.type === EntityType.POTION) {
        // Draw Potion
        const bob = Math.sin(Date.now() / 300) * 2;
        ctx.fillStyle = COLORS.potion;
        // Bottle shape
        ctx.beginPath();
        ctx.arc(ent.pos.x + 10, ent.pos.y + 15 + bob, 8, 0, Math.PI * 2);
        ctx.fill();
        ctx.fillRect(ent.pos.x + 7, ent.pos.y + bob, 6, 10);

        // Highlight
        ctx.fillStyle = 'rgba(255,255,255,0.6)';
        ctx.beginPath();
        ctx.arc(ent.pos.x + 8, ent.pos.y + 13 + bob, 2, 0, Math.PI * 2);
        ctx.fill();

        // Cork
        ctx.fillStyle = '#78350F';
        ctx.fillRect(ent.pos.x + 6, ent.pos.y - 2 + bob, 8, 4);
      }
      else if (ent.type === EntityType.SPIKE) {
        ctx.fillStyle = levelRef.current.spikeColor || COLORS.spike;
        ctx.beginPath();
        const numSpikes = Math.floor(ent.size.x / 10);
        for(let i=0; i<numSpikes; i++) {
            ctx.moveTo(ent.pos.x + i * 10, ent.pos.y + ent.size.y);
            ctx.lineTo(ent.pos.x + i * 10 + 5, ent.pos.y);
            ctx.lineTo(ent.pos.x + i * 10 + 10, ent.pos.y + ent.size.y);
        }
        ctx.fill();
      }
      else if (ent.type === EntityType.TROPHY) {
        ctx.fillStyle = COLORS.trophy;
        ctx.beginPath();
        ctx.moveTo(ent.pos.x + 5, ent.pos.y + 5);
        ctx.lineTo(ent.pos.x + 35, ent.pos.y + 5);
        ctx.bezierCurveTo(ent.pos.x + 35, ent.pos.y + 25, ent.pos.x + 5, ent.pos.y + 25, ent.pos.x + 5, ent.pos.y + 5);
        ctx.fill();
        ctx.fillStyle = COLORS.trophyBase;
        ctx.fillRect(ent.pos.x + 15, ent.pos.y + 25, 10, 5);
        ctx.fillRect(ent.pos.x + 10, ent.pos.y + 30, 20, 5);
        ctx.fillStyle = '#FFF';
        ctx.globalAlpha = 0.5;
        ctx.beginPath();
        ctx.arc(ent.pos.x + 15, ent.pos.y + 10, 3, 0, Math.PI * 2);
        ctx.fill();
        ctx.globalAlpha = 1.0;
      }
      else if (ent.type === EntityType.FLAG) {
         ctx.fillStyle = COLORS.gateLight || '#9CA3AF';
         ctx.fillRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);
         ctx.fillStyle = COLORS.gateDark || '#374151';
         ctx.beginPath();
         ctx.roundRect(ent.pos.x + 15, ent.pos.y + 20, ent.size.x - 30, ent.size.y - 20, 10);
         ctx.fill();
         ctx.strokeStyle = '#4B5563';
         ctx.lineWidth = 2;
         ctx.strokeRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);
      }
      else if (ent.type === EntityType.ENEMY) {
         ctx.fillStyle = ent.color || COLORS.enemy;

         if (ent.enemyVariant && ent.enemyVariant.startsWith('FAMILY')) {
             // DRAW FAMILY MEMBERS
             // Base Bear Body (White)
             ctx.fillStyle = '#FFFFFF';
             ctx.beginPath();
             ctx.roundRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y, 5);
             ctx.fill();

             // Ears
             ctx.beginPath();
             ctx.arc(ent.pos.x + 5, ent.pos.y + 2, 5, 0, Math.PI*2);
             ctx.arc(ent.pos.x + ent.size.x - 5, ent.pos.y + 2, 5, 0, Math.PI*2);
             ctx.fill();

             // Face
             ctx.fillStyle = '#FCD34D';
             const faceX = ent.pos.x + (ent.vel.x > 0 ? ent.size.x * 0.4 : 2);
             const faceW = ent.size.x * 0.5;
             const faceH = ent.size.y * 0.4;
             ctx.beginPath();
             ctx.roundRect(faceX, ent.pos.y + ent.size.y * 0.2, faceW, faceH, 3);
             ctx.fill();

             // Eyes
             ctx.fillStyle = '#000';
             ctx.beginPath();
             ctx.arc(faceX + faceW * 0.3, ent.pos.y + ent.size.y * 0.35, 2, 0, Math.PI*2);
             ctx.arc(faceX + faceW * 0.7, ent.pos.y + ent.size.y * 0.35, 2, 0, Math.PI*2);
             ctx.fill();

             // Accessories
             if (ent.enemyVariant === 'FAMILY_DAD') {
                 // Tie
                 ctx.fillStyle = '#EF4444';
                 ctx.beginPath();
                 ctx.moveTo(ent.pos.x + ent.size.x/2, ent.pos.y + ent.size.y * 0.6);
                 ctx.lineTo(ent.pos.x + ent.size.x/2 - 5, ent.pos.y + ent.size.y);
                 ctx.lineTo(ent.pos.x + ent.size.x/2 + 5, ent.pos.y + ent.size.y);
                 ctx.fill();
             } else if (ent.enemyVariant === 'FAMILY_MOM') {
                 // Scarf
                 ctx.fillStyle = '#EC4899'; // Pink
                 ctx.fillRect(ent.pos.x, ent.pos.y + ent.size.y * 0.5, ent.size.x, 4);
             }

         }
         else if (ent.enemyVariant === 'BAT' || ent.enemyVariant === 'BIRD') {
             // Draw Bat/Bird
             ctx.fillStyle = ent.color || COLORS.enemyBat;
             ctx.beginPath();
             // Bird Shape
             if (ent.enemyVariant === 'BIRD') {
                 // White/Grey Bird
                 ctx.moveTo(ent.pos.x, ent.pos.y + 10);
                 ctx.lineTo(ent.pos.x + 10, ent.pos.y + 15);
                 ctx.lineTo(ent.pos.x + 30, ent.pos.y + 10); // Beak
                 ctx.lineTo(ent.pos.x + 10, ent.pos.y + 5);
             } else {
                 ctx.arc(ent.pos.x + 15, ent.pos.y + 10, 10, 0, Math.PI * 2); // Body
             }
             ctx.fill();

             // Wings
             const wingFlap = Math.sin(Date.now() / 50) * 10;
             ctx.beginPath();
             ctx.moveTo(ent.pos.x + 5, ent.pos.y + 10);
             ctx.lineTo(ent.pos.x - 5, ent.pos.y + 5 + wingFlap);
             ctx.lineTo(ent.pos.x + 15, ent.pos.y + 10);
             ctx.lineTo(ent.pos.x + 35, ent.pos.y + 5 + wingFlap);
             ctx.lineTo(ent.pos.x + 25, ent.pos.y + 10);
             ctx.fill();

         } else if (ent.enemyVariant === 'UFO') {
             // Draw UFO
             ctx.fillStyle = COLORS.enemyUfo;
             // Saucer Body
             ctx.beginPath();
             ctx.ellipse(ent.pos.x + ent.size.x/2, ent.pos.y + ent.size.y * 0.7, ent.size.x/2, ent.size.y/4, 0, 0, Math.PI*2);
             ctx.fill();
             // Dome
             ctx.fillStyle = '#60A5FA';
             ctx.beginPath();
             ctx.arc(ent.pos.x + ent.size.x/2, ent.pos.y + ent.size.y * 0.5, ent.size.x/4, Math.PI, 0);
             ctx.fill();
             // Lights
             ctx.fillStyle = COLORS.ufoLight;
             for(let i=1; i<4; i++) {
                 ctx.beginPath();
                 ctx.arc(ent.pos.x + i * (ent.size.x/4), ent.pos.y + ent.size.y * 0.7, 2, 0, Math.PI*2);
                 ctx.fill();
             }

         } else if (ent.enemyVariant === 'ALIEN') {
             // Alien
             ctx.fillStyle = COLORS.enemyAlien;
             // Head
             ctx.beginPath();
             ctx.ellipse(ent.pos.x + 12, ent.pos.y + 8, 10, 8, 0, 0, Math.PI*2);
             ctx.fill();
             // Body
             ctx.fillRect(ent.pos.x + 7, ent.pos.y + 16, 10, 15);
             // Eyes
             ctx.fillStyle = '#000';
             ctx.beginPath();
             ctx.ellipse(ent.pos.x + 8, ent.pos.y + 8, 2, 3, -0.2, 0, Math.PI*2);
             ctx.ellipse(ent.pos.x + 16, ent.pos.y + 8, 2, 3, 0.2, 0, Math.PI*2);
             ctx.fill();

         } else if (ent.enemyVariant === 'METEOR') {
             // Meteor (Rotated rock)
             ctx.save();
             ctx.translate(ent.pos.x + ent.size.x/2, ent.pos.y + ent.size.y/2);
             ctx.rotate(Date.now() / 200);
             ctx.fillStyle = COLORS.meteor;
             ctx.beginPath();
             // Rugged shape
             ctx.moveTo(-15, -10);
             ctx.lineTo(10, -15);
             ctx.lineTo(15, 5);
             ctx.lineTo(5, 15);
             ctx.lineTo(-10, 10);
             ctx.lineTo(-15, -10);
             ctx.fill();
             // Detail
             ctx.fillStyle = 'rgba(0,0,0,0.2)';
             ctx.beginPath();
             ctx.arc(-5, -5, 4, 0, Math.PI*2);
             ctx.arc(5, 5, 3, 0, Math.PI*2);
             ctx.fill();
             ctx.restore();

         } else if (ent.enemyVariant === 'SLIME') {
             ctx.beginPath();
             ctx.arc(ent.pos.x + 15, ent.pos.y + 15, 15, Math.PI, 0); // Top
             ctx.lineTo(ent.pos.x + 30, ent.pos.y + 20);
             ctx.lineTo(ent.pos.x, ent.pos.y + 20);
             ctx.fill();
         } else if (ent.enemyVariant === 'FISH') {
             // Draw Fish
             ctx.fillStyle = ent.color || COLORS.enemyFish;
             const facing = ent.vel.x > 0 ? 1 : -1;
             ctx.save();
             ctx.translate(ent.pos.x + ent.size.x/2, ent.pos.y + ent.size.y/2);
             ctx.scale(facing, 1);
             ctx.beginPath();
             ctx.ellipse(0, 0, 15, 10, 0, 0, Math.PI*2);
             ctx.fill();
             ctx.beginPath();
             ctx.moveTo(-12, 0);
             ctx.lineTo(-20, -8);
             ctx.lineTo(-20, 8);
             ctx.fill();
             ctx.fillStyle = '#FFF';
             ctx.beginPath();
             ctx.arc(8, -3, 3, 0, Math.PI*2);
             ctx.fill();
             ctx.fillStyle = '#000';
             ctx.beginPath();
             ctx.arc(9, -3, 1, 0, Math.PI*2);
             ctx.fill();
             ctx.restore();
         } else if (ent.enemyVariant === 'SKELETON') {
             // Draw Skeleton
             ctx.fillStyle = COLORS.enemySkeleton;
             ctx.fillRect(ent.pos.x + 10, ent.pos.y + 15, 5, 20);
             ctx.fillRect(ent.pos.x + 5, ent.pos.y + 18, 15, 2);
             ctx.fillRect(ent.pos.x + 5, ent.pos.y + 24, 15, 2);
             ctx.fillRect(ent.pos.x + 5, ent.pos.y, 15, 15);
             ctx.fillStyle = '#000';
             ctx.fillRect(ent.pos.x + 8, ent.pos.y + 5, 2, 2);
             ctx.fillRect(ent.pos.x + 14, ent.pos.y + 5, 2, 2);
         } else if (ent.enemyVariant === 'ZOMBIE') {
             // Draw Zombie
             ctx.fillStyle = COLORS.enemyZombie; 
             ctx.fillRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);
             ctx.fillStyle = '#374151'; 
             ctx.fillRect(ent.pos.x, ent.pos.y + 20, ent.size.x, ent.size.y - 20);
             ctx.fillStyle = COLORS.enemyZombie;
             const lookDir = ent.vel.x > 0 ? 1 : -1;
             ctx.fillRect(ent.pos.x + (lookDir > 0 ? 15 : -5), ent.pos.y + 15, 20, 6);
             ctx.fillStyle = '#000';
             ctx.fillRect(ent.pos.x + (lookDir > 0 ? 18 : 6), ent.pos.y + 8, 4, 4);
             ctx.fillStyle = 'red'; 
             ctx.fillRect(ent.pos.x + (lookDir > 0 ? 19 : 7), ent.pos.y + 9, 2, 2);
         } else if (ent.enemyVariant === 'MUMMY') {
             // Draw Mummy
             ctx.fillStyle = COLORS.enemyMummy;
             ctx.fillRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);
             ctx.fillStyle = '#D4D4D4';
             ctx.fillRect(ent.pos.x, ent.pos.y + 10, ent.size.x, 2);
             ctx.fillRect(ent.pos.x, ent.pos.y + 20, ent.size.x, 2);
             ctx.fillRect(ent.pos.x, ent.pos.y + 30, ent.size.x, 2);
             ctx.fillStyle = '#000';
             ctx.fillRect(ent.pos.x + 5, ent.pos.y + 8, ent.size.x - 10, 6);
             ctx.fillStyle = 'red';
             const lookDir = ent.vel.x > 0 ? 1 : 0;
             ctx.fillRect(ent.pos.x + (lookDir ? 18 : 8), ent.pos.y + 10, 4, 2);
         } else if (ent.enemyVariant === 'SPIDER') {
             // Draw Web line
             if (ent.initialY !== undefined) {
                 ctx.strokeStyle = '#FFF';
                 ctx.lineWidth = 1;
                 ctx.beginPath();
                 ctx.moveTo(ent.pos.x + ent.size.x/2, ent.initialY - 200); 
                 ctx.lineTo(ent.pos.x + ent.size.x/2, ent.pos.y + 5);
                 ctx.stroke();
             }
             // Draw Spider
             ctx.fillStyle = COLORS.enemySpider;
             ctx.beginPath();
             ctx.arc(ent.pos.x + 15, ent.pos.y + 12, 12, 0, Math.PI*2);
             ctx.fill();
             // Eyes
             ctx.fillStyle = COLORS.spiderEye;
             ctx.fillRect(ent.pos.x + 8, ent.pos.y + 14, 4, 4);
             ctx.fillRect(ent.pos.x + 18, ent.pos.y + 14, 4, 4);
         } else {
             // Default Box
             ctx.fillRect(ent.pos.x, ent.pos.y, ent.size.x, ent.size.y);
         }

         // Eyes (General) for standard enemies
         if (!['FISH', 'SKELETON', 'MUMMY', 'SPIDER', 'BAT', 'ZOMBIE', 'BIRD', 'UFO', 'ALIEN', 'METEOR', 'FAMILY_DAD', 'FAMILY_MOM', 'FAMILY_BRO', 'FAMILY_SIS'].includes(ent.enemyVariant || '')) {
            ctx.fillStyle = '#fff';
            const lookDir = ent.vel.x > 0 ? 1 : 0;
            const eyeSize = ent.size.x * 0.2;
            ctx.fillRect(ent.pos.x + (lookDir ? ent.size.x * 0.6 : ent.size.x * 0.1), ent.pos.y + ent.size.y * 0.2, eyeSize, eyeSize);
            ctx.fillStyle = '#000';
            const pupilSize = eyeSize * 0.5;
            ctx.fillRect(ent.pos.x + (lookDir ? ent.size.x * 0.65 : ent.size.x * 0.15), ent.pos.y + ent.size.y * 0.25, pupilSize, pupilSize);
         }

         if ((ent.enemyVariant === 'TANK' || ent.enemyVariant === 'MUMMY' || ent.enemyVariant === 'SKELETON' || ent.enemyVariant === 'ZOMBIE' || ent.enemyVariant === 'UFO' || ent.enemyVariant === 'METEOR') && ent.health && ent.maxHealth) {
             const hpPct = ent.health / ent.maxHealth;
             ctx.fillStyle = 'red';
             ctx.fillRect(ent.pos.x, ent.pos.y - 10, ent.size.x, 5);
             ctx.fillStyle = 'green';
             ctx.fillRect(ent.pos.x, ent.pos.y - 10, ent.size.x * hpPct, 5);
         }
      }
    });

    // 4. Draw Bullets (Projectiles)
    bullets.forEach(b => {
        if (isShovelLevel) {
            // Draw Spinning Shovel
            ctx.save();
            ctx.translate(b.pos.x, b.pos.y);
            const rot = (Date.now() / 50) % (Math.PI * 2);
            ctx.rotate(rot);

            ctx.fillStyle = COLORS.shovelHandle;
            ctx.fillRect(-5, -2, 10, 4); // Handle
            ctx.fillStyle = COLORS.shovel;
            ctx.beginPath(); // Spade head
            ctx.moveTo(5, -6);
            ctx.lineTo(17, -6);
            ctx.lineTo(20, 0);
            ctx.lineTo(17, 6);
            ctx.lineTo(5, 6);
            ctx.fill();

            ctx.restore();
        } else if (isShurikenLevel) {
            // Draw Spinning Shuriken
            ctx.save();
            ctx.translate(b.pos.x, b.pos.y);
            const rot = (Date.now() / 20) % (Math.PI * 2);
            ctx.rotate(rot);

            ctx.fillStyle = COLORS.shuriken;
            // 4-point star
            ctx.beginPath();
            for(let i=0; i<4; i++) {
                ctx.rotate(Math.PI / 2);
                ctx.moveTo(0, 0);
                ctx.lineTo(5, 2);
                ctx.lineTo(10, 0);
                ctx.lineTo(5, -2);
                ctx.lineTo(0, 0);
            }
            ctx.fill();
            ctx.beginPath();
            ctx.arc(0,0, 2, 0, Math.PI*2); // Center hole
            ctx.fillStyle = '#000';
            ctx.fill();

            ctx.restore();

        } else if (isLaserLevel) {
            // Laser Beam
            ctx.strokeStyle = COLORS.laserBeam;
            ctx.lineWidth = 4;
            ctx.lineCap = 'round';
            const len = 25;
            const dir = b.vel.x > 0 ? 1 : -1;
            ctx.shadowBlur = 10;
            ctx.shadowColor = COLORS.laserBeam;

            ctx.beginPath();
            ctx.moveTo(b.pos.x, b.pos.y);
            ctx.lineTo(b.pos.x + len * dir, b.pos.y);
            ctx.stroke();

            ctx.shadowBlur = 0;

        } else if (isBowLevel) {
            // Draw Bow
            ctx.strokeStyle = COLORS.projectile;
            ctx.lineWidth = 2;
            const arrowLen = 15;
            const dir = b.vel.x > 0 ? 1 : -1;

            ctx.beginPath();
            ctx.moveTo(b.pos.x, b.pos.y);
            ctx.lineTo(b.pos.x + arrowLen * dir, b.pos.y);
            ctx.moveTo(b.pos.x + arrowLen * dir, b.pos.y);
            ctx.lineTo(b.pos.x + (arrowLen - 5) * dir, b.pos.y - 3);
            ctx.moveTo(b.pos.x + arrowLen * dir, b.pos.y);
            ctx.lineTo(b.pos.x + (arrowLen - 5) * dir, b.pos.y + 3);
            ctx.stroke();
        } else {
            // Gun
            ctx.fillStyle = COLORS.projectile;
            ctx.beginPath();
            ctx.arc(b.pos.x + b.size.x/2, b.pos.y + b.size.y/2, b.size.x/2, 0, Math.PI * 2);
            ctx.fill();
            ctx.shadowBlur = 5;
            ctx.shadowColor = 'white';
            ctx.fill();
            ctx.shadowBlur = 0;
        }
    });

    // 5. Draw Player
    if (player.isInvulnerable && Math.floor(Date.now() / 100) % 2 === 0) {
       ctx.globalAlpha = 0.5;
    }

    // Draw Bear / Ninja / Astronaut
    if (isSpaceLevel) {
        // ASTRONAUT BEAR
        ctx.fillStyle = COLORS.astroSuit;
        ctx.beginPath();
        // Bulky Suit
        ctx.roundRect(player.pos.x - 2, player.pos.y - 2, player.size.x + 4, player.size.y + 4, 8);
        ctx.fill();

        // Backpack (Life Support)
        ctx.fillStyle = '#CBD5E1';
        if (player.facingRight) {
             ctx.fillRect(player.pos.x - 6, player.pos.y + 5, 6, 15);
        } else {
             ctx.fillRect(player.pos.x + player.size.x, player.pos.y + 5, 6, 15);
        }

        // Helmet/Visor
        ctx.fillStyle = COLORS.astroVisor;
        const faceX = player.facingRight ? player.pos.x + 8 : player.pos.x + 2;
        ctx.beginPath();
        ctx.roundRect(faceX, player.pos.y + 4, 20, 14, 6);
        ctx.fill();

        // Reflection
        ctx.fillStyle = 'rgba(255,255,255,0.4)';
        ctx.beginPath();
        ctx.ellipse(faceX + 14, player.pos.y + 8, 4, 2, -0.5, 0, Math.PI*2);
        ctx.fill();

    } else if (isTrainLevel) {
        // NINJA BEAR
        ctx.fillStyle = COLORS.ninjaBody;
        ctx.beginPath();
        ctx.roundRect(player.pos.x, player.pos.y, player.size.x, player.size.y, 5);
        ctx.fill();

        // Red Sash/Headband
        ctx.fillStyle = COLORS.ninjaSash;
        ctx.fillRect(player.pos.x, player.pos.y + 5, player.size.x, 6);
        // Headband tails
        if (player.vel.x !== 0 || player.vel.y !== 0) {
             const tailDir = player.facingRight ? -1 : 1;
             ctx.beginPath();
             ctx.moveTo(player.pos.x + player.size.x/2, player.pos.y + 8);
             ctx.lineTo(player.pos.x + player.size.x/2 + (tailDir * 20), player.pos.y + 5);
             ctx.lineTo(player.pos.x + player.size.x/2 + (tailDir * 20), player.pos.y + 11);
             ctx.fill();
        }

        // Eyes
        const faceX = player.facingRight ? player.pos.x + 12 : player.pos.x + 2;
        ctx.fillStyle = '#FFF'; // White eyes for ninja mask
        const eyeOffsetX = player.facingRight ? 4 : 0;
        ctx.beginPath();
        ctx.ellipse(faceX + 4 + eyeOffsetX, player.pos.y + 8, 3, 2, 0, 0, Math.PI*2);
        ctx.ellipse(faceX + 10 + eyeOffsetX, player.pos.y + 8, 3, 2, 0, 0, Math.PI*2);
        ctx.fill();

    } else {
        // STANDARD BEAR
        ctx.fillStyle = COLORS.bear;

        if (isSeaLevel) {
            // ... Mer-bear drawing (existing) ...
            const tailWiggle = Math.sin(Date.now() / 100) * 3;
            ctx.fillStyle = COLORS.tail;
            ctx.beginPath();
            if (player.facingRight) {
                ctx.moveTo(player.pos.x + 10, player.pos.y + 20); 
                ctx.lineTo(player.pos.x - 10, player.pos.y + 35 + tailWiggle); 
                ctx.lineTo(player.pos.x - 10, player.pos.y + 15 + tailWiggle); 
            } else {
                ctx.moveTo(player.pos.x + 20, player.pos.y + 20); 
                ctx.lineTo(player.pos.x + 40, player.pos.y + 35 + tailWiggle); 
                ctx.lineTo(player.pos.x + 40, player.pos.y + 15 + tailWiggle); 
            }
            ctx.fill();
            ctx.fillStyle = COLORS.bear;
            ctx.beginPath();
            ctx.roundRect(player.pos.x, player.pos.y, player.size.x, 20, 5);
            ctx.fill();
        } else {
            ctx.beginPath();
            ctx.roundRect(player.pos.x, player.pos.y, player.size.x, player.size.y, 5);
            ctx.fill();
        }

        // Ears
        ctx.fillStyle = COLORS.bear;
        ctx.beginPath();
        ctx.arc(player.pos.x + 5, player.pos.y + 2, 6, 0, Math.PI*2);
        ctx.arc(player.pos.x + player.size.x - 5, player.pos.y + 2, 6, 0, Math.PI*2);
        ctx.fill();

        // Face
        ctx.fillStyle = player.drunkTimer > 0 ? COLORS.bearFaceDrunk : COLORS.bearFace;
        const faceX = player.facingRight ? player.pos.x + 12 : player.pos.x + 2;
        ctx.beginPath();
        ctx.roundRect(faceX, player.pos.y + 8, 16, 12, 4);
        ctx.fill();

        ctx.fillStyle = '#000';
        const eyeOffsetX = player.facingRight ? 4 : 0;
        ctx.beginPath();
        ctx.arc(faceX + 4 + eyeOffsetX, player.pos.y + 12, 2, 0, Math.PI*2);
        ctx.arc(faceX + 10 + eyeOffsetX, player.pos.y + 12, 2, 0, Math.PI*2);
        ctx.fill();
        ctx.beginPath();
        ctx.ellipse(faceX + 7 + eyeOffsetX, player.pos.y + 16, 3, 2, 0, 0, Math.PI*2);
        ctx.fill();
    }

    // WEAPON DRAWING (Held)
    if (isShovelLevel) {
        if (player.shootCooldown < SHOOT_COOLDOWN - 5) {
            ctx.save();
            const pivotX = player.pos.x + player.size.x/2;
            const pivotY = player.pos.y + player.size.y/2;
            ctx.translate(pivotX, pivotY);
            const rotation = player.facingRight ? -0.5 : -2.5;
            ctx.rotate(rotation);
            ctx.fillStyle = COLORS.shovelHandle;
            ctx.fillRect(0, -2, 20, 4); // Handle
            ctx.fillStyle = COLORS.shovel;
            ctx.beginPath(); // Spade head
            ctx.moveTo(20, -6);
            ctx.lineTo(32, -6);
            ctx.lineTo(35, 0);
            ctx.lineTo(32, 6);
            ctx.lineTo(20, 6);
            ctx.fill();
            ctx.restore();
        }

    } else if (isShurikenLevel) {
        // Ninja Star held in hand
        if (player.shootCooldown < SHOOT_COOLDOWN - 2) {
            ctx.fillStyle = COLORS.shuriken;
            const handX = player.facingRight ? player.pos.x + 25 : player.pos.x - 5;
            const handY = player.pos.y + 15;
            ctx.beginPath();
            ctx.arc(handX, handY, 4, 0, Math.PI*2);
            ctx.fill();
        }

    } else if (isLaserLevel) {
        // Laser Gun
        ctx.fillStyle = COLORS.laserGun;
        const gunX = player.facingRight ? player.pos.x + 22 : player.pos.x - 8;
        const gunY = player.pos.y + 18;
        // Sci-fi shape
        ctx.beginPath();
        ctx.moveTo(gunX, gunY);
        ctx.lineTo(gunX + 12, gunY);
        ctx.lineTo(gunX + 15, gunY + 4);
        ctx.lineTo(gunX + 2, gunY + 4);
        ctx.fill();
        // Glow tip
        ctx.fillStyle = '#A7F3D0';
        ctx.fillRect(gunX + (player.facingRight? 12 : 0), gunY + 1, 2, 2);

    } else if (isBowLevel) {
        // Draw Bow
        ctx.strokeStyle = '#8B4513';
        ctx.lineWidth = 2;
        const bowX = player.facingRight ? player.pos.x + 25 : player.pos.x - 5;
        const bowY = player.pos.y + 15;

        ctx.beginPath();
        ctx.arc(bowX, bowY, 10, (player.facingRight ? -Math.PI/2 : Math.PI/2), (player.facingRight ? Math.PI/2 : 1.5 * Math.PI));
        ctx.stroke();

        ctx.strokeStyle = '#EEE';
        ctx.lineWidth = 1;
        ctx.beginPath();
        ctx.moveTo(bowX, bowY - 10);
        ctx.lineTo(bowX, bowY + 10);
        ctx.stroke();
    } else {
        // Draw Gun (Standard) - BUT NOT IN ARCTIC
        if (!isTrainLevel && !isArcticLevel) { 
            ctx.fillStyle = COLORS.gun;
            const gunX = player.facingRight ? player.pos.x + 20 : player.pos.x - 5;
            const gunY = player.pos.y + 15;
            ctx.fillRect(gunX, gunY, 15, 6);
            ctx.fillRect(player.facingRight ? gunX : gunX + 10, gunY + 2, 5, 8);
        }
    }

    ctx.globalAlpha = 1.0;
    ctx.restore();

    // 6. Draw Boss HUD (Last Enemy)
    const boss = entitiesRef.current.find(e => e.type === EntityType.ENEMY && e.maxHealth && e.maxHealth > 2 && Math.abs(e.pos.x - player.pos.x) < 500 && !e.isDead);
    if (boss) {
        const hpPct = (boss.health || 0) / (boss.maxHealth || 1);
        const barWidth = 400;
        const barX = (CANVAS_WIDTH - barWidth) / 2;
        const barY = CANVAS_HEIGHT - 30;

        ctx.fillStyle = 'rgba(0, 0, 0, 0.5)';
        ctx.fillRect(barX - 2, barY - 2, barWidth + 4, 14);

        ctx.fillStyle = '#1F2937';
        ctx.fillRect(barX, barY, barWidth, 10);

        ctx.fillStyle = '#DC2626';
        ctx.fillRect(barX, barY, barWidth * hpPct, 10);

        ctx.fillStyle = '#FFF';
        ctx.font = '10px "Press Start 2P"';
        ctx.textAlign = 'center';
        ctx.fillText("BOSS", barX + barWidth/2, barY - 5);
    }

    // 7. Draw Weather Particles (Overlay)
    if (weather === 'RAIN') {
        ctx.strokeStyle = 'rgba(173, 216, 230, 0.6)';
        ctx.lineWidth = 2;
        particlesRef.current.forEach(p => {
            if (!p.color) { 
                ctx.beginPath();
                ctx.moveTo(p.x, p.y);
                ctx.lineTo(p.x - 2, p.y + 10);
                ctx.stroke();
            }
        });
    } else if (weather === 'SEA' || weather === 'TOMB' || weather === 'TRAIN' || weather === 'ARCTIC' || weather === 'SNOW') {
         // Tomb dust / Sea bubbles / Train wind / Snow
         particlesRef.current.forEach(p => {
             if (p.color && (p.color.startsWith('rgba') || p.color === '#D97706' || p.color === '#FFFFFF')) { 
                ctx.fillStyle = p.color;
                ctx.beginPath();
                ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
                ctx.fill();
             }
        });
    }

    // Draw Fire/Effect Particles (On top)
    particlesRef.current.forEach(p => {
        if (p.color && !p.color.startsWith('rgba') && p.color !== '#525252' && p.color !== '#D97706' && p.color !== '#FFFFFF') {
            ctx.fillStyle = p.color;
            ctx.globalAlpha = p.life;
            ctx.beginPath();
            ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
            ctx.fill();
            ctx.globalAlpha = 1.0;
        }
    });
  };

  const loop = () => {
    update();
    draw();
    requestRef.current = requestAnimationFrame(loop);
  };

  useEffect(() => {
    requestRef.current = requestAnimationFrame(loop);
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [gameState.status]);

  // Touch handlers
  const handleTouchStart = (key: string) => { keysRef.current[key] = true; };
  const handleTouchEnd = (key: string) => { keysRef.current[key] = false; };

  return (
    <div className="relative w-full max-w-[800px] mx-auto">
        <canvas
        ref={canvasRef}
        width={CANVAS_WIDTH}
        height={CANVAS_HEIGHT}
        className="block bg-black rounded-lg shadow-2xl border-4 border-gray-700 w-full h-auto"
        style={{ imageRendering: 'pixelated' }}
        />

        {/* VIRTUAL TOUCH CONTROLS (Only show on touch devices or always for now) */}
        <div className="absolute inset-0 pointer-events-none flex flex-col justify-end pb-4 px-4 md:hidden">
            <div className="flex justify-between w-full pointer-events-auto">
                <div className="flex gap-4">
                    <button 
                        className="w-16 h-16 bg-white/20 backdrop-blur-sm rounded-full flex items-center justify-center active:bg-white/40 touch-none"
                        onTouchStart={() => handleTouchStart('ArrowLeft')}
                        onTouchEnd={() => handleTouchEnd('ArrowLeft')}
                    >
                        <ArrowLeft className="w-8 h-8 text-white" />
                    </button>
                    <button 
                        className="w-16 h-16 bg-white/20 backdrop-blur-sm rounded-full flex items-center justify-center active:bg-white/40 touch-none"
                        onTouchStart={() => handleTouchStart('ArrowRight')}
                        onTouchEnd={() => handleTouchEnd('ArrowRight')}
                    >
                        <ArrowRight className="w-8 h-8 text-white" />
                    </button>
                </div>
                <div className="flex gap-4">
                    <button 
                        className="w-16 h-16 bg-red-500/30 backdrop-blur-sm rounded-full flex items-center justify-center active:bg-red-500/50 touch-none"
                        onTouchStart={() => {
                            keysRef.current['KeyF'] = true;
                            // Reset key after frame to prevent spam if needed, but cooldown handles it
                            setTimeout(() => keysRef.current['KeyF'] = false, 100);
                        }}
                    >
                        <Crosshair className="w-8 h-8 text-white" />
                    </button>
                    <button 
                        className="w-16 h-16 bg-blue-500/30 backdrop-blur-sm rounded-full flex items-center justify-center active:bg-blue-500/50 touch-none"
                        onTouchStart={() => {
                            keysRef.current['Space'] = true;
                            // Trigger jump buffer
                            playerRef.current.jumpBufferTimer = JUMP_BUFFER;
                        }}
                        onTouchEnd={() => handleTouchEnd('Space')}
                    >
                        <ArrowUp className="w-8 h-8 text-white" />
                    </button>
                </div>
            </div>
        </div>
    </div>
  );
};

export enum GameStatus {
  MENU = 'MENU',
  INTRO = 'INTRO', // New: Opening Cinematic
  PLAYING = 'PLAYING',
  GAME_OVER = 'GAME_OVER',
  LEVEL_COMPLETE = 'LEVEL_COMPLETE',
  VICTORY = 'VICTORY', // Kept for internal logic check
  OUTRO = 'OUTRO', // New: Ending Cinematic
  CREDITS = 'CREDITS', 
  REVIVE_PROMPT = 'REVIVE_PROMPT',
  HIDDEN_OUTRO = 'HIDDEN_OUTRO' // New: Hidden Ending Cinematic
}

export enum EntityType {
  PLAYER = 'PLAYER',
  PLATFORM = 'PLATFORM',
  BREAKABLE_WALL = 'BREAKABLE_WALL', // New: Diggable terrain
  COIN = 'COIN',
  ENEMY = 'ENEMY',
  SPIKE = 'SPIKE',
  FLAG = 'FLAG', // Gate/Door
  TROPHY = 'TROPHY', // New win condition
  LAVA = 'LAVA',
  PROJECTILE = 'PROJECTILE',
  SPAWNER = 'SPAWNER',
  WINE = 'WINE',
  POTION = 'POTION' // New Health Item
}

export type WeatherType = 'SUNNY' | 'RAIN' | 'SNOW' | 'CAVE' | 'SEA' | 'TOMB' | 'TRAIN' | 'SPACE' | 'ARCTIC';
export type EnemyVariant = 'NORMAL' | 'TANK' | 'FAST' | 'BAT' | 'SLIME' | 'FISH' | 'SKELETON' | 'MUMMY' | 'SPIDER' | 'ZOMBIE' | 'BIRD' | 'ALIEN' | 'UFO' | 'METEOR' | 'FAMILY_DAD' | 'FAMILY_MOM' | 'FAMILY_BRO' | 'FAMILY_SIS';

export interface Vector {
  x: number;
  y: number;
}

export interface Entity {
  id: string;
  type: EntityType;
  pos: Vector;
  size: Vector;
  vel: Vector;
  color?: string;
  isDead?: boolean;

  // Friendly / Follow logic
  isFollowing?: boolean;
  followOffset?: number; // Random offset to prevent stacking

  // Enemy specific
  patrolStart?: number; 
  patrolEnd?: number;   
  enemyVariant?: EnemyVariant;
  health?: number;
  maxHealth?: number;
  initialY?: number; // For Spiders

  // Spawner specific
  spawnCooldown?: number;
  timeUntilSpawn?: number;
  spawnVariant?: EnemyVariant;
}

export interface Player extends Entity {
  isGrounded: boolean;
  facingRight: boolean;
  isInvulnerable: boolean;
  invulnerableTimer: number;
  shootCooldown: number;
  drunkTimer: number; // For the wine power-up
  // Physics optimization
  coyoteTimer: number; // Allows jumping shortly after leaving ground
  jumpBufferTimer: number; // Remembers jump press slightly before hitting ground
  // Melee state
  isAttacking?: boolean;
  attackTimer?: number;
}

export interface LevelData {
  id: number;
  name: string;
  width: number;
  height: number;
  entities: Entity[];
  spawnPoint: Vector;
  backgroundColor: string;
  groundColor?: string; // Custom ground color
  spikeColor?: string;  // Custom spike color
  weather: WeatherType;
}

export interface GameState {
  status: GameStatus;
  currentLevelId: number;
  score: number;
  lives: number;
  maxLives: number; // Dynamic max health
  coinsCollected: number;
}

import { LevelData, EntityType, EnemyVariant } from './types';
import { CANVAS_HEIGHT, COLORS, TILE_SIZE } from './constants';

const createPlatform = (x: number, y: number, w: number, h: number, id: string) => ({
  id, type: EntityType.PLATFORM, pos: { x: x * TILE_SIZE, y: CANVAS_HEIGHT - y * TILE_SIZE }, size: { x: w * TILE_SIZE, y: h * TILE_SIZE }, vel: { x: 0, y: 0 }
});

// Helper for Wall: y represents the top-most point (grid units from bottom). 
// To block full screen (height 450, roughly 11.25 tiles), we use y=12 and h=12.
const createWall = (x: number, y: number, w: number, h: number, id: string) => ({
  id, type: EntityType.BREAKABLE_WALL, pos: { x: x * TILE_SIZE, y: CANVAS_HEIGHT - y * TILE_SIZE }, size: { x: w * TILE_SIZE, y: h * TILE_SIZE }, vel: { x: 0, y: 0 }
});

const createCoin = (x: number, y: number, id: string) => ({
  id, type: EntityType.COIN, pos: { x: x * TILE_SIZE + 10, y: CANVAS_HEIGHT - y * TILE_SIZE + 10 }, size: { x: 20, y: 20 }, vel: { x: 0, y: 0 }
});

const createWine = (x: number, y: number, id: string) => ({
  id, type: EntityType.WINE, pos: { x: x * TILE_SIZE + 10, y: CANVAS_HEIGHT - y * TILE_SIZE + 5 }, size: { x: 20, y: 30 }, vel: { x: 0, y: 0 }
});

const createPotion = (x: number, y: number, id: string) => ({
  id, type: EntityType.POTION, pos: { x: x * TILE_SIZE + 10, y: CANVAS_HEIGHT - y * TILE_SIZE + 5 }, size: { x: 20, y: 25 }, vel: { x: 0, y: 0 }
});

const createSpike = (x: number, y: number, w: number, id: string) => ({
  id, type: EntityType.SPIKE, pos: { x: x * TILE_SIZE, y: CANVAS_HEIGHT - y * TILE_SIZE }, size: { x: w * TILE_SIZE, y: TILE_SIZE / 2 }, vel: { x: 0, y: 0 }
});

const createTrophy = (x: number, y: number, id: string) => ({
  id, type: EntityType.TROPHY, pos: { x: x * TILE_SIZE, y: CANVAS_HEIGHT - y * TILE_SIZE - 40 }, size: { x: 40, y: 40 }, vel: { x: 0, y: 0 }
});

const createSpawner = (x: number, y: number, variant: EnemyVariant, cooldownFrames: number, id: string) => ({
  id,
  type: EntityType.SPAWNER,
  pos: { x: x * TILE_SIZE, y: CANVAS_HEIGHT - y * TILE_SIZE },
  size: { x: TILE_SIZE, y: TILE_SIZE },
  vel: { x: 0, y: 0 },
  spawnVariant: variant,
  spawnCooldown: cooldownFrames,
  timeUntilSpawn: 0
});

const createFamily = (x: number, y: number, variant: EnemyVariant, id: string) => {
    let width = 30;
    let height = 30;

    if (variant === 'FAMILY_DAD') {
        width = 40;
        height = 40;
    } else if (variant === 'FAMILY_BRO' || variant === 'FAMILY_SIS') {
        width = 20;
        height = 20;
    }

    return {
        id,
        type: EntityType.ENEMY, // Using Enemy type for movement update logic, but will be treated as friendly
        pos: { x: x * TILE_SIZE, y: CANVAS_HEIGHT - y * TILE_SIZE - height },
        size: { x: width, y: height },
        vel: { x: 0, y: 0 }, // Wait for player
        patrolStart: -9999, // Endless patrol
        patrolEnd: 99999,
        enemyVariant: variant,
        health: 999,
        color: '#FFFFFF',
        isFollowing: false,
        followOffset: Math.random() * 20 + 30 // 30-50 distance
    };
};

// Enemy Factory
const createEnemy = (x: number, y: number, range: number, variant: EnemyVariant, id: string) => {
  let width = 30;
  let height = 30;
  let speed = 2;
  let health = 1;
  let color = COLORS.enemy;

  if (variant === 'TANK') {
    width = 50;
    height = 50;
    speed = 1;
    health = 3;
    color = COLORS.enemyTank;
  } else if (variant === 'FAST') {
    width = 25;
    height = 25;
    speed = 4;
    health = 1;
    color = COLORS.enemyFast;
  } else if (variant === 'BAT' || variant === 'BIRD') {
    width = 30;
    height = 20;
    speed = 3;
    health = 1;
    color = variant === 'BIRD' ? COLORS.enemyBird : COLORS.enemyBat;
  } else if (variant === 'SLIME') {
    width = 30;
    height = 20;
    speed = 1;
    health = 2;
    color = COLORS.enemySlime;
  } else if (variant === 'FISH') {
    width = 35;
    height = 25;
    speed = 2.5;
    health = 1;
    color = COLORS.enemyFish;
  } else if (variant === 'SKELETON') {
    width = 25;
    height = 45;
    speed = 2;
    health = 2;
    color = COLORS.enemySkeleton;
  } else if (variant === 'MUMMY') {
    width = 30;
    height = 45;
    speed = 1;
    health = 4;
    color = COLORS.enemyMummy;
  } else if (variant === 'ZOMBIE') {
    width = 30;
    height = 45;
    speed = 1.5;
    health = 3;
    color = COLORS.enemyZombie;
  } else if (variant === 'SPIDER') {
    width = 30;
    height = 25;
    speed = 2; // Vertical speed
    health = 1;
    color = COLORS.enemySpider;
  } else if (variant === 'ALIEN') {
    width = 25;
    height = 35;
    speed = 2;
    health = 2;
    color = COLORS.enemyAlien;
  } else if (variant === 'UFO') {
    width = 40;
    height = 25;
    speed = 4;
    health = 2;
    color = COLORS.enemyUfo;
  } else if (variant === 'METEOR') {
      width = 30;
      height = 30;
      speed = 3;
      health = 1;
      color = COLORS.meteor;
  }

  const enemy = {
    id, 
    type: EntityType.ENEMY, 
    pos: { x: x * TILE_SIZE, y: CANVAS_HEIGHT - y * TILE_SIZE - height }, 
    size: { x: width, y: height }, 
    vel: { x: speed, y: 0 }, 
    patrolStart: x * TILE_SIZE, 
    patrolEnd: (x + range) * TILE_SIZE,
    enemyVariant: variant,
    health,
    maxHealth: health,
    color,
    initialY: CANVAS_HEIGHT - y * TILE_SIZE - height
  };

  if (variant === 'SPIDER') {
      enemy.vel.x = 0; // Spiders only move Y
      enemy.vel.y = speed;
  }
  if (variant === 'UFO') {
      // UFOs can fly
  }

  return enemy;
};

// Helper to create a train car platform
// length: number of tiles wide
const createTrainCar = (startX: number, length: number, idPrefix: string) => {
    return createPlatform(startX, 2, length, 1, `${idPrefix}_floor`);
};

