                    {/* Decorative Elements around Logo */}
                    <Star className="absolute -top-6 -right-6 text-yellow-300 w-10 h-10 animate-spin-slow drop-shadow-lg" />
                    <Sparkles className="absolute -bottom-4 -left-8 text-white w-8 h-8 animate-pulse" />
                </div>

                <div className="mt-4 px-6 py-1 bg-black/60 rounded-full border border-white/20 backdrop-blur-sm shadow-xl">
