  const [highScore, setHighScore] = useState(0);
  const [gameSessionId, setGameSessionId] = useState(0); // Used to force component remount
  const [cheatBuffer, setCheatBuffer] = useState(""); // Buffer for cheat code

  useEffect(() => {
    const saved = localStorage.getItem('bear_adventure_highscore');
    if (saved) setHighScore(parseInt(saved));
  }, []);

  useEffect(() => {
    if (gameState.score > highScore) {
      setHighScore(gameState.score);
      localStorage.setItem('bear_adventure_highscore', gameState.score.toString());
    }
  }, [gameState.score, highScore]);

  // SECRET CODE LISTENER
  useEffect(() => {
      const handleSecretCode = (e: KeyboardEvent) => {
          if (gameState.status === GameStatus.CREDITS) {
              const newBuffer = (cheatBuffer + e.key).slice(-8); // Keep last 8 chars
              setCheatBuffer(newBuffer);

              if (newBuffer === "20181018") {
                  audio.playPowerUp();
                  // Start Hidden Level 999
                  startGame(999); 
              }
          }
      };

      window.addEventListener('keydown', handleSecretCode);
      return () => window.removeEventListener('keydown', handleSecretCode);
  }, [gameState.status, cheatBuffer]);

  const startGame = (levelId: number = 1) => {
    audio.init(); 
    setGameSessionId(prev => prev + 1); 

    // Reset buffer
    setCheatBuffer("");

    // Only play intro for the first level
    if (levelId === 1) {
        setGameState({
            ...INITIAL_STATE,
            status: GameStatus.INTRO,
            currentLevelId: levelId
        });
        // Play mystery music for intro
        audio.startBGM('SPACE'); 
    } else {
        setGameState({
            ...INITIAL_STATE,
            status: GameStatus.PLAYING,
            currentLevelId: levelId
        });
        // GameCanvas will handle BGM initialization for the specific level
    }
  };

  const handleCinematicComplete = () => {
    if (gameState.status === GameStatus.INTRO) {
      setGameState(prev => ({ ...prev, status: GameStatus.PLAYING }));
      // Music will be handled by GameCanvas mounting
    } else if (gameState.status === GameStatus.OUTRO) {
      setGameState(prev => ({ ...prev, status: GameStatus.CREDITS }));
      audio.startBGM('CREDITS'); // Special Cheerful 'YouYou' Theme
    } else if (gameState.status === GameStatus.HIDDEN_OUTRO) {
      setGameState(prev => ({ ...prev, status: GameStatus.CREDITS }));
      audio.startBGM('CREDITS');
    }
  };

  const handleLevelComplete = () => {
    // Hidden Level Check
    if (gameState.currentLevelId === 999) {
        setGameState(prev => ({ ...prev, status: GameStatus.HIDDEN_OUTRO }));
        audio.playWin();
        return;
    }

    // Normal Progression
    if (gameState.currentLevelId >= levels.length - 1) { // -1 because hidden level is in array
       setGameState(prev => ({ ...prev, status: GameStatus.OUTRO }));
       audio.playWin();
    } else {
       setGameState(prev => ({ ...prev, status: GameStatus.LEVEL_COMPLETE }));
    }
  };

  const handleNextLevel = () => {
    setGameState(prev => ({
      ...prev,
      status: GameStatus.PLAYING,
      currentLevelId: prev.currentLevelId + 1
    }));
  };

  const handlePlayerHit = () => {
     setGameState(prev => {
        const newLives = prev.lives - 1;
        if (newLives <= 0) {
            return { ...prev, lives: 0, status: GameStatus.REVIVE_PROMPT };
        }
        return { ...prev, lives: newLives };
     });
  };

  const handleRevive = () => {
    if (gameState.coinsCollected >= REVIVE_COST) {
        setGameState(prev => ({
            ...prev,
            lives: prev.maxLives, 
            coinsCollected: prev.coinsCollected - REVIVE_COST,
            status: GameStatus.PLAYING
        }));
    }
  };

  const handleGiveUp = () => {
    setGameState(prev => ({ ...prev, status: GameStatus.GAME_OVER }));
  };

  const currentLevel = levels.find(l => l.id === gameState.currentLevelId);

  return (
    <div className="min-h-screen bg-zinc-900 flex flex-col items-center justify-center p-4 font-sans select-none text-white">

      {/* Header / HUD */}
      <div className="w-full max-w-[800px] flex justify-between items-center mb-4 px-4 py-2 bg-zinc-800/80 backdrop-blur rounded-xl border-2 border-zinc-700 shadow-lg z-30">
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-1 text-red-400">
            {/* Dynamic Heart Rendering */}
            {Array.from({ length: gameState.maxLives }).map((_, i) => (
                <Heart 
                    key={i} 
                    className={`w-6 h-6 ${i < gameState.lives ? 'fill-current text-red-500' : 'text-red-900/50 fill-none'}`} 
                />
            ))}
          </div>
          <div className="flex items-center gap-2 text-yellow-400">
            <Coins className="w-6 h-6 fill-current" />
            <span className="pixel-font text-xl">{gameState.coinsCollected}</span>
          </div>
        </div>

        <div className="text-center">
            <h1 className="text-sm text-gray-400 uppercase tracking-widest font-bold">{currentLevel?.name || "ADVENTURE"}</h1>
        </div>

        <div className="flex flex-col items-end">
          <span className="text-xs text-gray-400">分数 (SCORE)</span>
          <span className="pixel-font text-xl text-white">{gameState.score.toString().padStart(6, '0')}</span>
        </div>
      </div>

      {/* Main Game Area */}
      <div className="relative group w-full max-w-[800px] h-[450px] bg-black rounded-lg shadow-2xl overflow-hidden border-4 border-gray-700">

        {/* Render Game Canvas */}
        {/* Only render game canvas if playing or complete/gameover overlay is on top, NOT during cinematic to save resources */}
        {gameState.status !== GameStatus.MENU && gameState.status !== GameStatus.INTRO && gameState.status !== GameStatus.OUTRO && gameState.status !== GameStatus.HIDDEN_OUTRO && gameState.status !== GameStatus.CREDITS && (
            <GameCanvas 
            key={`${gameState.currentLevelId}-${gameSessionId}`} 
            levelId={gameState.currentLevelId}
            gameState={gameState}
            setGameState={setGameState}
            onLevelComplete={handleLevelComplete}
            onPlayerHit={handlePlayerHit}
            onGameOver={() => setGameState(prev => ({ ...prev, lives: 0, status: GameStatus.REVIVE_PROMPT }))} 
            />
        )}

        {/* OVERLAYS */}

        {/* CINEMATICS */}
        {gameState.status === GameStatus.INTRO && (
            <CinematicView scenes={INTRO_SCENES} onComplete={handleCinematicComplete} />
        )}

        {gameState.status === GameStatus.OUTRO && (
            <CinematicView scenes={OUTRO_SCENES} onComplete={handleCinematicComplete} />
        )}

        {gameState.status === GameStatus.HIDDEN_OUTRO && (
            <CinematicView scenes={HIDDEN_OUTRO_SCENES} onComplete={handleCinematicComplete} />
        )}

        {/* MENU - REDESIGNED */}
        {gameState.status === GameStatus.MENU && (
          <div className="absolute inset-0 flex flex-col justify-between items-center z-10 bg-[url('https://images.unsplash.com/photo-1511497584788-876760111969?q=80&w=2664&auto=format&fit=crop')] bg-cover bg-center overflow-hidden">
            {/* Clean Dark Overlay */}
            <div className="absolute inset-0 bg-black/30 pointer-events-none"></div>

            {/* Subtle Texture */}
            <div className="absolute inset-0 opacity-10 bg-[url('https://www.transparenttextures.com/patterns/stardust.png')] pointer-events-none"></div>

            {/* --- TOP SECTION: TITLE LOGO --- */}
            <div className="relative z-20 mt-16 flex flex-col items-center">
                <div className="relative group cursor-default">
                    {/* Main Title - Clean & Atmospheric */}
                    <h1 className="pixel-font text-5xl md:text-7xl font-black text-white drop-shadow-[0_5px_0_rgba(0,0,0,1)] tracking-tight">
                        小熊大冒险
                    </h1>
                    {/* Subtitle */}
                    <div className="mt-2 text-center">
                        <span className="pixel-font text-[10px] md:text-xs text-yellow-300 tracking-[0.5em] font-bold bg-black/50 px-4 py-1 rounded-full uppercase border border-white/20">
                            Little Bear's Adventure
                        </span>
                    </div>
                </div>
            </div>

            {/* --- MIDDLE SECTION: SPACER --- */}
            <div className="flex-grow"></div>

            {/* --- BOTTOM SECTION: ACTIONS --- */}
            <div className="relative z-20 w-full max-w-md px-6 pb-8 flex flex-col items-center gap-6">

                {/* Main Play Button */}
                <button 
                    onClick={() => startGame(1)}
                    className="group relative w-full max-w-[280px] h-16 transition-all hover:scale-105 active:scale-95"
                >
                    {/* Button Shadow */}
                    <div className="absolute inset-0 bg-yellow-700 rounded-full translate-y-1"></div>
                    {/* Button Face */}
                    <div className="relative h-full bg-gradient-to-r from-yellow-400 to-yellow-500 rounded-full border-2 border-yellow-300 flex items-center justify-center gap-3 shadow-xl">
                        <Play className="w-6 h-6 text-yellow-900 fill-current" />
                        <span className="pixel-font text-2xl text-yellow-900 tracking-widest font-bold">开始游戏</span>
                    </div>
                </button>

                {/* Level Selection Panel */}
                <div className="w-full bg-black/70 backdrop-blur-sm p-4 rounded-xl border border-white/10 shadow-2xl">
                    <div className="flex items-center justify-between mb-3 border-b border-white/10 pb-2">
                        <div className="flex items-center gap-2 text-gray-300">
                            <Map className="w-4 h-4 text-yellow-500" />
                            <span className="text-xs font-bold">章节选择</span>
                        </div>
                        <span className="text-[10px] text-gray-500">SELECT CHAPTER</span>
                    </div>

                    <div className="grid grid-cols-4 gap-3">
                        {levels.filter(l => l.id !== 999).map((level) => (
                        <button 
                            key={level.id}
                            onClick={() => startGame(level.id)}
                            className="group relative h-10 overflow-hidden rounded bg-white/10 hover:bg-yellow-500 hover:text-black border border-white/20 transition-all flex items-center justify-center"
                        >
                            <span className="pixel-font text-sm font-bold group-hover:scale-110 transition-transform">{level.id}</span>
                        </button>
                        ))}
                    </div>
                </div>

                {/* Footer Controls Info - CHINESE */}
                <div className="flex gap-4 text-[10px] text-gray-300 font-bold bg-black/60 px-4 py-2 rounded-full border border-white/10 backdrop-blur-md">
                    <div className="flex items-center gap-1">
                        <Move className="w-3 h-3 text-yellow-400" /> 
                        <span>移动: 方向键</span>
                    </div>
                    <div className="flex items-center gap-1">
                        <ArrowUpFromLine className="w-3 h-3 text-green-400" />
                        <span>跳跃: 空格</span>
                    </div>
                    <div className="flex items-center gap-1">
                        <Target className="w-3 h-3 text-red-400" />
                        <span>攻击: F</span>
                    </div>
                </div>
            </div>
          </div>
        )}

        {/* REVIVE PROMPT */}
        {gameState.status === GameStatus.REVIVE_PROMPT && (
          <div className="absolute inset-0 bg-red-900/90 flex flex-col items-center justify-center text-center rounded-lg z-10">
             <Heart className="w-16 h-16 text-red-500 mb-4 animate-pulse" />
             <h2 className="pixel-font text-3xl text-white mb-4">你受伤了!</h2>
             <p className="text-white/80 mb-6">生命值已耗尽。</p>

             <div className="flex flex-col gap-4 w-64">
                <button 
                  onClick={handleRevive}
                  disabled={gameState.coinsCollected < REVIVE_COST}
                  className={`border-b-4 font-bold py-3 px-4 rounded-lg pixel-font transition-all ${
                    gameState.coinsCollected >= REVIVE_COST 
                    ? 'bg-yellow-400 text-yellow-900 hover:bg-yellow-300 border-yellow-600 cursor-pointer' 
                    : 'bg-gray-600 text-gray-400 border-gray-700 cursor-not-allowed opacity-50'
                  }`}
                >
                  原地复活 ({REVIVE_COST} 金币)
                </button>

                <button 
                  onClick={handleGiveUp}
                  className="bg-transparent border-2 border-white/20 text-white hover:bg-white/10 font-bold py-2 px-4 rounded-lg pixel-font text-sm"
                >
                  放弃 (重新开始)
                </button>
             </div>

             {gameState.coinsCollected < REVIVE_COST && (
                <p className="text-red-300 text-xs mt-2">金币不足!</p>
             )}
          </div>
        )}

        {/* GAME OVER */}
        {gameState.status === GameStatus.GAME_OVER && (
          <div className="absolute inset-0 bg-black/95 flex flex-col items-center justify-center text-center rounded-lg z-10">
             <Skull className="w-16 h-16 text-gray-400 mb-4" />
             <h2 className="pixel-font text-4xl text-white mb-2">游戏结束</h2>
             <p className="text-white/80 mb-6">本次收集金币: {gameState.coinsCollected}</p>
             <button 
                  onClick={() => setGameState(INITIAL_STATE)}
                  className="bg-white text-black hover:bg-gray-200 border-b-4 border-gray-400 font-bold py-3 px-8 rounded-lg pixel-font"
                >
                  返回标题
             </button>
          </div>
        )}

        {/* LEVEL COMPLETE */}
        {gameState.status === GameStatus.LEVEL_COMPLETE && (
          <div className="absolute inset-0 bg-blue-900/90 flex flex-col items-center justify-center text-center rounded-lg z-10">
             <Trophy className="w-16 h-16 text-yellow-400 mb-4 animate-pulse" />
             <h2 className="pixel-font text-4xl text-white mb-2">关卡完成!</h2>
             <p className="text-white/80 mb-6">准备好迎接下一个挑战了吗?</p>
             <button 
                  onClick={handleNextLevel}
                  className="bg-yellow-400 text-yellow-900 hover:bg-yellow-300 border-b-4 border-yellow-600 font-bold py-3 px-8 rounded-lg pixel-font"
                >
                  下一关
             </button>
          </div>
        )}

        {/* CREDITS */}
        {gameState.status === GameStatus.CREDITS && (
          <div className="absolute inset-0 bg-black/95 flex flex-col items-center justify-center text-center rounded-lg z-20 animate-fade-in">
             <Star className="w-16 h-16 text-yellow-300 mb-6 animate-spin-slow" />

             <h2 className="pixel-font text-2xl text-white mb-8">THE END</h2>

             <div className="space-y-6 mb-12">
                 <div>
                    <p className="text-gray-400 text-sm mb-1">感谢制作者</p>
                    <p className="text-xl font-bold text-white">Gemini AI</p>
                 </div>

                 <div>
                    <p className="text-gray-400 text-sm mb-1">特别鸣谢</p>
                    <p className="text-2xl font-bold text-pink-400 pixel-font">右右小朋友</p>
                 </div>

                 <div className="mt-4">
                    <p className="text-gray-500 text-xs">最终得分: {gameState.score}</p>
                 </div>
             </div>

             <button 
                  onClick={() => setGameState(INITIAL_STATE)}
                  className="bg-white text-black hover:bg-gray-200 border-b-4 border-gray-400 font-bold py-3 px-8 rounded-lg pixel-font"
                >
                  回到主菜单
             </button>
          </div>
        )}

      </div>

      <div className="mt-4 text-gray-500 text-xs">
         最高分: {highScore}
      </div>
    </div>
  );
};

export default App;

// 游戏状态枚举
export enum GameStatus {
  MENU = 'MENU',             // 主菜单
  INTRO = 'INTRO',           // 开场动画
  PLAYING = 'PLAYING',       // 游戏进行中
  GAME_OVER = 'GAME_OVER',   // 游戏结束
  LEVEL_COMPLETE = 'LEVEL_COMPLETE', // 关卡完成
  VICTORY = 'VICTORY',       // 通关（保留字段）
  OUTRO = 'OUTRO',           // 结局动画
  CREDITS = 'CREDITS',       // 感谢名单（包含隐藏秘籍输入）
  REVIVE_PROMPT = 'REVIVE_PROMPT',   // 复活提示
  HIDDEN_OUTRO = 'HIDDEN_OUTRO'      // 隐藏结局动画
}

// 实体类型枚举：定义游戏中所有物体的类别
export enum EntityType {
  PLAYER = 'PLAYER',                 // 玩家（小熊）
  PLATFORM = 'PLATFORM',             // 地面/平台
  BREAKABLE_WALL = 'BREAKABLE_WALL', // 可破坏的墙壁
  COIN = 'COIN',                     // 金币
  ENEMY = 'ENEMY',                   // 敌人
  SPIKE = 'SPIKE',                   // 尖刺（陷阱）
  FLAG = 'FLAG',                     // 旗帜（旧版终点）
  TROPHY = 'TROPHY',                 // 奖杯（关卡终点）
  LAVA = 'LAVA',                     // 岩浆
  PROJECTILE = 'PROJECTILE',         // 子弹/投掷物
  SPAWNER = 'SPAWNER',               // 刷怪笼
  WINE = 'WINE',                     // 道具：酒（加速+无敌）
  POTION = 'POTION'                  // 道具：药水（回血）
}

// 天气/环境类型
export type WeatherType = 'SUNNY' | 'RAIN' | 'SNOW' | 'CAVE' | 'SEA' | 'TOMB' | 'TRAIN' | 'SPACE' | 'ARCTIC';

// 敌人变种类型
export type EnemyVariant = 'NORMAL' | 'TANK' | 'FAST' | 'BAT' | 'SLIME' | 'FISH' | 'SKELETON' | 'MUMMY' | 'SPIDER' | 'ZOMBIE' | 'BIRD' | 'ALIEN' | 'UFO' | 'METEOR' | 'FAMILY_DAD' | 'FAMILY_MOM' | 'FAMILY_BRO' | 'FAMILY_SIS';

// 基础向量接口
export interface Vector {
  x: number;
  y: number;
}

// 基础实体接口：游戏中所有物体的基类
export interface Entity {
  id: string;           // 唯一标识符
  type: EntityType;     // 类型
  pos: Vector;          // 位置 (x, y)
  size: Vector;         // 尺寸 (宽, 高)
  vel: Vector;          // 速度向量
  color?: string;       // 颜色（可选）
  isDead?: boolean;     // 是否已销毁

  // 友好NPC/跟随逻辑
  isFollowing?: boolean; // 是否正在跟随玩家
  followOffset?: number; // 跟随时的随机偏移量，防止重叠

  // 敌人特有属性
  patrolStart?: number; // 巡逻起始X坐标
  patrolEnd?: number;   // 巡逻结束X坐标
  enemyVariant?: EnemyVariant; // 敌人变种
  health?: number;      // 当前生命值
  maxHealth?: number;   // 最大生命值
  initialY?: number;    // 初始Y坐标（用于蜘蛛等悬挂怪物）

  // 刷怪笼特有属性
  spawnCooldown?: number; // 生成冷却时间（帧数）
  timeUntilSpawn?: number;// 距离下次生成的计时器
  spawnVariant?: EnemyVariant; // 生成的怪物类型
}

// 玩家接口：继承自实体，增加玩家特有状态
export interface Player extends Entity {
  isGrounded: boolean;      // 是否在地面上
  facingRight: boolean;     // 朝向（true为右）
  isInvulnerable: boolean;  // 是否处于无敌状态
  invulnerableTimer: number;// 无敌时间计时器
  shootCooldown: number;    // 射击冷却
  drunkTimer: number;       // "醉酒"状态计时器（吃了酒道具）

  // 物理手感优化
  coyoteTimer: number;      // "土狼时间"：离开平台后的一小段时间内仍允许跳跃
  jumpBufferTimer: number;  // "跳跃预输入"：落地前按跳跃键，落地瞬间自动跳跃

  // 近战/交互状态
  isAttacking?: boolean;
  attackTimer?: number;
}

// 关卡数据结构
export interface LevelData {
  id: number;
  name: string;         // 英文名称
  nameCn: string;       // 中文名称 (新增)
  width: number;        // 关卡总宽度
  height: number;       // 关卡高度
  entities: Entity[];   // 包含的所有实体
  spawnPoint: Vector;   // 玩家出生点
  backgroundColor: string; // 背景色
  groundColor?: string; // 地面颜色
  spikeColor?: string;  // 尖刺颜色
  weather: WeatherType; // 天气类型
}

// 全局游戏状态
export interface GameState {
  status: GameStatus;       // 当前流程状态
  currentLevelId: number;   // 当前关卡ID
  score: number;            // 得分
  lives: number;            // 当前生命
  maxLives: number;         // 最大生命上限（可动态增加）
  coinsCollected: number;   // 金币收集数量
}

import { LevelData, EntityType, EnemyVariant } from './types';
import { CANVAS_HEIGHT, COLORS, TILE_SIZE } from './constants';

const createPlatform = (x: number, y: number, w: number, h: number, id: string) => ({
  id, type: EntityType.PLATFORM, pos: { x: x * TILE_SIZE, y: CANVAS_HEIGHT - y * TILE_SIZE }, size: { x: w * TILE_SIZE, y: h * TILE_SIZE }, vel: { x: 0, y: 0 }
});

// Helper for Wall
const createWall = (x: number, y: number, w: number, h: number, id: string) => ({
  id, type: EntityType.BREAKABLE_WALL, pos: { x: x * TILE_SIZE, y: CANVAS_HEIGHT - y * TILE_SIZE }, size: { x: w * TILE_SIZE, y: h * TILE_SIZE }, vel: { x: 0, y: 0 }
});

// **终点封锁墙** (不可破坏，用于物理阻挡，但视觉上会根据ID进行特殊渲染)
// id 参数将决定它的渲染外观 (例如 'end_gate_flowers', 'end_gate_cave' 等)
const createEndGate = (x: number, id: string) => ({
  id, 
  type: EntityType.PLATFORM, 
  pos: { x: x * TILE_SIZE, y: -500 }, 
  size: { x: TILE_SIZE * 20, y: CANVAS_HEIGHT + 1000 }, 
  vel: { x: 0, y: 0 }
});

const createCoin = (x: number, y: number, id: string) => ({
  id, type: EntityType.COIN, pos: { x: x * TILE_SIZE + 10, y: CANVAS_HEIGHT - y * TILE_SIZE + 10 }, size: { x: 20, y: 20 }, vel: { x: 0, y: 0 }
});

const createWine = (x: number, y: number, id: string) => ({
  id, type: EntityType.WINE, pos: { x: x * TILE_SIZE + 10, y: CANVAS_HEIGHT - y * TILE_SIZE + 5 }, size: { x: 20, y: 30 }, vel: { x: 0, y: 0 }
});

const createPotion = (x: number, y: number, id: string) => ({
  id, type: EntityType.POTION, pos: { x: x * TILE_SIZE + 10, y: CANVAS_HEIGHT - y * TILE_SIZE + 5 }, size: { x: 20, y: 25 }, vel: { x: 0, y: 0 }
});

const createSpike = (x: number, y: number, w: number, id: string) => ({
  id, type: EntityType.SPIKE, pos: { x: x * TILE_SIZE, y: CANVAS_HEIGHT - y * TILE_SIZE }, size: { x: w * TILE_SIZE, y: TILE_SIZE / 2 }, vel: { x: 0, y: 0 }
});

const createTrophy = (x: number, y: number, id: string) => ({
  id, type: EntityType.TROPHY, pos: { x: x * TILE_SIZE, y: CANVAS_HEIGHT - y * TILE_SIZE - 40 }, size: { x: 40, y: 40 }, vel: { x: 0, y: 0 }
});

const createSpawner = (x: number, y: number, variant: EnemyVariant, cooldownFrames: number, id: string) => ({
  id,
  type: EntityType.SPAWNER,
  pos: { x: x * TILE_SIZE, y: CANVAS_HEIGHT - y * TILE_SIZE },
  size: { x: TILE_SIZE, y: TILE_SIZE },
  vel: { x: 0, y: 0 },
  spawnVariant: variant,
  spawnCooldown: cooldownFrames,
  timeUntilSpawn: 0
});

const createFamily = (x: number, y: number, variant: EnemyVariant, id: string) => {
    let width = 30;
    let height = 30;

    if (variant === 'FAMILY_DAD') {
        width = 40;
        height = 40;
    } else if (variant === 'FAMILY_BRO' || variant === 'FAMILY_SIS') {
        width = 20;
        height = 20;
    }

    return {
        id,
        type: EntityType.ENEMY, 
        pos: { x: x * TILE_SIZE, y: CANVAS_HEIGHT - y * TILE_SIZE - height },
        size: { x: width, y: height },
        vel: { x: 0, y: 0 }, 
        patrolStart: -9999, 
        patrolEnd: 99999,
        enemyVariant: variant,
        health: 999,
        color: '#FFFFFF',
        isFollowing: false,
        followOffset: Math.random() * 20 + 30 
    };
};

const createEnemy = (x: number, y: number, range: number, variant: EnemyVariant, id: string) => {
  let width = 30;
  let height = 30;
  let speed = 2;
  let health = 1;
  let color = COLORS.enemy;

  if (variant === 'TANK') { width = 50; height = 50; speed = 1; health = 3; color = COLORS.enemyTank; } 
  else if (variant === 'FAST') { width = 25; height = 25; speed = 4; health = 1; color = COLORS.enemyFast; } 
  else if (variant === 'BAT' || variant === 'BIRD') { width = 30; height = 20; speed = 3; health = 1; color = variant === 'BIRD' ? COLORS.enemyBird : COLORS.enemyBat; } 
  else if (variant === 'SLIME') { width = 30; height = 20; speed = 1; health = 2; color = COLORS.enemySlime; } 
  else if (variant === 'FISH') { width = 35; height = 25; speed = 2.5; health = 1; color = COLORS.enemyFish; } 
  else if (variant === 'SKELETON') { width = 25; height = 45; speed = 2; health = 2; color = COLORS.enemySkeleton; } 
  else if (variant === 'MUMMY') { width = 30; height = 45; speed = 1; health = 4; color = COLORS.enemyMummy; } 
  else if (variant === 'ZOMBIE') { width = 30; height = 45; speed = 1.5; health = 3; color = COLORS.enemyZombie; } 
  else if (variant === 'SPIDER') { width = 30; height = 25; speed = 2; health = 1; color = COLORS.enemySpider; } 
  else if (variant === 'ALIEN') { width = 25; height = 35; speed = 2; health = 2; color = COLORS.enemyAlien; } 
  else if (variant === 'UFO') { width = 40; height = 25; speed = 4; health = 2; color = COLORS.enemyUfo; } 
  else if (variant === 'METEOR') { width = 30; height = 30; speed = 3; health = 1; color = COLORS.meteor; }

  const enemy = {
    id, 
    type: EntityType.ENEMY, 
    pos: { x: x * TILE_SIZE, y: CANVAS_HEIGHT - y * TILE_SIZE - height }, 
    size: { x: width, y: height }, 
    vel: { x: speed, y: 0 }, 
    patrolStart: x * TILE_SIZE, 
    patrolEnd: (x + range) * TILE_SIZE,
    enemyVariant: variant,
    health,
    maxHealth: health,
    color,
    initialY: CANVAS_HEIGHT - y * TILE_SIZE - height
  };

  if (variant === 'SPIDER') { enemy.vel.x = 0; enemy.vel.y = speed; }

  return enemy;
};

// 重构：创建连接的客运车厢 (Passanger Car)
// 为了视觉连续性，车厢高度设为2格(80px)，y=2
const createPassengerCar = (startX: number, length: number, idPrefix: string) => {
    return createPlatform(startX, 2, length, 2, `${idPrefix}_passengercar`);
};


